
export const quotes = [
    // 인생 (Life)
    { text: "검사하지 않은 삶은 살 가치가 없다.", author: "소크라테스", category: "인생", keyword: "thinking", commentary: "자신의 생각과 행동을 끊임없이 되돌아보는 성찰의 중요성을 강조합니다." },
    { text: "인생은 가까이서 보면 비극이지만 멀리서 보면 희극이다.", author: "찰리 채플린", category: "인생", keyword: "stage", commentary: "지금의 고통도 시간의 흐름 속에서 삶의 한 조각으로 받아들일 수 있다는 위로를 줍니다." },
    { text: "삶이 있는 한 희망은 있다.", author: "키케로", category: "인생", keyword: "sunrise", commentary: "생존 그 자체가 가장 큰 기회이자 모든 가능성의 시작점임을 일깨워 줍니다." },
    { text: "죽는 날까지 하늘을 우러러 한 점 부끄럼이 없기를.", author: "윤동주", category: "인생", keyword: "night sky", commentary: "어두운 시대 속에서도 잃지 않았던 순수한 양심과 성찰의 자세를 보여줍니다." },
    { text: "인생은 자전거를 타는 것과 같다. 균형을 잡으려면 계속 움직여야 한다.", author: "아인슈타인", category: "인생", keyword: "bicycle", commentary: "안주하는 순간 균형을 잃게 됩니다. 삶은 끊임없는 도전과 전진의 과정입니다." },
    { text: "오늘이 내 남은 생의 첫날이다.", author: "영화 '아메리칸 뷰티'", category: "인생", keyword: "rose petals", commentary: "과거에 얽매이지 말고, 매일을 새로운 시작으로 여기는 태도의 중요성을 강조합니다." },
    { text: "인생에서 가장 큰 영광은 결코 넘어지지 않는 데 있는 것이 아니라 넘어질 때마다 일어서는 데 있다.", author: "넬슨 만델라", category: "인생", keyword: "mountain peak", commentary: "실패 자체가 아닌, 실패를 딛고 다시 일어서는 회복탄력성이 진정한 강함입니다." },
    { text: "우리는 모두 시궁창에 있지만, 우리 중 몇몇은 별을 보고 있다.", author: "오스카 와일드", category: "인생", keyword: "stars", commentary: "어떤 절망적인 상황 속에서도 희망과 이상을 꿈꾸는 자세의 가치를 말합니다." },
    { text: "결국, 당신이 만들어낸 사랑이 당신이 가져가는 사랑과 같을 것이다.", author: "비틀즈", category: "인생", keyword: "love", commentary: "삶의 마지막 순간에 남는 것은 우리가 세상에 베푼 사랑의 총합임을 시사합니다." },

    // 성공 (Success)
    { text: "혁신은 리더와 추종자를 구분하는 잣대다.", author: "스티브 잡스", category: "성공", keyword: "technology", commentary: "단순히 현상을 유지하는 것이 아니라, 새로운 가치를 창조하는 자가 시대를 이끕니다." },
    { text: "성공은 최종적인 것이 아니며, 실패는 치명적인 것이 아니다. 중요한 것은 계속 나아갈 용기다.", author: "윈스턴 처칠", category: "성공", keyword: "persistence", commentary: "결과에 일희일비하지 않고, 어떤 상황에서도 도전을 멈추지 않는 끈기가 성공의 본질입니다." },
    { text: "나는 실패한 적이 없다. 단지 효과가 없는 만 가지 방법을 발견했을 뿐이다.", author: "토마스 에디슨", category: "성공", keyword: "lightbulb", commentary: "실패를 과정의 일부로 여기고 배움의 기회로 삼는 긍정적 사고방식의 힘을 보여줍니다." },
    { text: "당신이 할 수 있다고 믿든, 할 수 없다고 믿든, 당신이 옳다.", author: "헨리 포드", category: "성공", keyword: "belief", commentary: "자신의 신념이 행동의 한계를 결정하며, 결국 현실을 만들어낸다는 자기실현적 예언을 말합니다." },
    { text: "위대한 일을 하는 유일한 방법은 당신이 하는 일을 사랑하는 것이다.", author: "스티브 잡스", category: "성공", keyword: "passion", commentary: "열정은 지치지 않는 동기 부여의 원천이며, 탁월한 결과물을 만드는 핵심 요소입니다." },
    { text: "평범한 일을 비범하게 하는 것이 성공의 열쇠다.", author: "부커 T. 워싱턴", category: "성공", keyword: "craftsmanship", commentary: "일상적인 과업에 쏟는 정성과 탁월함이 위대한 성취의 기반이 됩니다." },
    { text: "가장 큰 위험은 아무런 위험도 감수하지 않으려는 것이다.", author: "마크 저커버그", category: "성공", keyword: "network", commentary: "빠르게 변하는 세상에서 현상 유지는 가장 확실한 실패 전략일 수 있습니다." },
    { text: "나는 내가 성공의 정의를 내리는 방식이 아니라, 실패를 어떻게 다루는지를 통해 나를 판단한다.", author: "세레나 윌리엄스", category: "성공", keyword: "tennis court", commentary: "좌절 후 다시 일어서는 능력이야말로 진정한 챔피언의 자질임을 보여줍니다." },

    // 지혜 (Wisdom)
    { text: "아는 것은 사랑하는 것이다.", author: "레오나르도 다빈치", category: "지혜", keyword: "vitruvian man", commentary: "대상에 대한 깊은 이해와 앎이 진정한 애정과 관심으로 이어진다는 통찰입니다." },
    { text: "어리석은 자는 자기가 현명하다고 생각하지만, 현명한 자는 자기가 어리석다는 것을 안다.", author: "윌리엄 셰익스피어", category: "지혜", keyword: "theater mask", commentary: "자신의 무지를 아는 '메타인지'야말로 진정한 지혜의 출발점임을 강조합니다." },
    { text: "어제로부터 배우고, 오늘을 위해 살고, 내일을 희망하라. 중요한 것은 질문을 멈추지 않는 것이다.", author: "아인슈타인", category: "지혜", keyword: "compass", commentary: "과거의 경험, 현재의 삶, 미래의 희망을 연결하는 호기심과 탐구 정신의 중요성을 말합니다." },
    { text: "마음의 평화는 외부에서 오는 것이 아니라, 당신의 내면에서 만들어진다.", author: "달라이 라마", category: "지혜", keyword: "zen garden", commentary: "상황에 대한 우리의 반응과 태도야말로 내면의 평화를 결정하는 핵심 요소입니다." },
    { text: "천 리 길도 한 걸음부터.", author: "노자", category: "지혜", keyword: "path", commentary: "아무리 거대한 목표라도, 결국 지금 내딛는 작은 첫걸음에서 시작됨을 잊지 말아야 합니다." },
    { text: "가장 깊은 강이 가장 조용히 흐른다.", author: "퀸투스 쿠르티우스 루푸스", category: "지혜", keyword: "river", commentary: "진정한 지혜와 깊이를 가진 사람은 요란하게 자신을 드러내지 않는다는 의미입니다." },
    { text: "통제할 수 없는 것들을 걱정하는 것은 에너지를 낭비하는 것이다.", author: "에픽테토스", category: "지혜", keyword: "stoic statue", commentary: "우리가 바꿀 수 있는 자신의 생각과 행동에 집중하는 것이 스토아 철학의 핵심입니다." },

    // 영화 (Movies)
    { text: "두려움은 정신을 죽이는 작은 죽음이다.", author: "영화 '듄'", category: "영화", keyword: "desert planet", commentary: "두려움에 굴복하는 순간, 우리의 이성과 잠재력은 마비됩니다. 이를 직시하고 통과해야 합니다." },
    { text: "집중하고, 느끼고, 생각해. 너의 직감을 믿어.", author: "영화 '스타워즈'", category: "영화", keyword: "galaxy", commentary: "때로는 논리적인 분석보다 내면의 목소리와 직관이 더 정확한 길을 알려줄 수 있습니다." },
    { text: "과거는 아플 수 있지. 하지만 둘 중 하나야. 도망치든가, 배우든가.", author: "영화 '라이온 킹'", category: "영화", keyword: "savanna", commentary: "과거의 트라우마를 회피할 것인가, 성장의 발판으로 삼을 것인가의 선택은 우리에게 달려있습니다." },
    { text: "희망은 좋은 것이다. 어쩌면 가장 좋은 것일지도 모른다. 그리고 좋은 것은 결코 죽지 않는다.", author: "영화 '쇼생크 탈출'", category: "영화", keyword: "hope sunrise", commentary: "어떤 절망적인 상황 속에서도 희망을 간직하는 것의 숭고한 가치를 보여줍니다." },
    { text: "우리가 누구인지를 보여주는 것은 우리의 능력이 아니라 우리의 선택이다.", author: "영화 '해리 포터'", category: "영화", keyword: "magic", commentary: "타고난 재능보다 매 순간 어떤 가치를 선택하며 살아가는지가 우리의 본질을 결정합니다." },
    { text: "어머니는 항상 인생이 초콜릿 상자와 같다고 말씀하셨어요. 어떤 것을 잡을지 절대 알 수 없죠.", author: "영화 '포레스트 검프'", category: "영화", keyword: "chocolate box", commentary: "인생의 예측 불가능성을 긍정하고, 주어진 모든 순간을 순수하게 받아들이는 태도를 상징합니다." },
    { text: "왜 넘어져야 하는지 알아? 다시 일어서는 법을 배우기 위해서다.", author: "영화 '배트맨 비긴즈'", category: "영화", keyword: "dark city", commentary: "실패와 좌절은 끝이 아니라, 더 강해지기 위한 필수적인 과정임을 강조합니다." },
    { text: "어떤 사람들에게는, 믿을 수 없는 일만이 유일하게 믿을 수 있는 일이다.", author: "영화 '라이프 오브 파이'", category: "영화", keyword: "ocean boat", commentary: "때로는 이성으로 설명할 수 없는 경이로운 이야기가 우리에게 더 깊은 진실을 줄 수 있습니다." },
    { text: "꿈을 꾸는 사람들을 위해. 그들이 바보 같다고 할지라도.", author: "영화 '라라랜드'", category: "영화", keyword: "city of stars", commentary: "현실의 벽 앞에서 좌절하더라도, 꿈을 향한 열정과 도전을 응원하는 메시지입니다." },
    { text: "우린 답을 찾을 거야. 늘 그랬듯이.", author: "영화 '인터스텔라'", category: "영화", keyword: "space travel", commentary: "절망적인 상황에서도 포기하지 않는 인류의 위대한 탐험 정신과 희망을 담고 있습니다." },
    { text: "진정한 사랑은 다른 사람의 행복이 나의 행복보다 우선되는 것이다.", author: "영화 '겨울왕국'", category: "영화", keyword: "snow queen", commentary: "자신을 희생해서라도 상대방을 위하는 마음이 진정한 사랑의 본질임을 말합니다." },

    // 드라마 (Drama)
    { text: "길은 모두에게 열려있지만, 모두가 그 길을 갈 수 있는 것은 아니다.", author: "드라마 '미생'", category: "드라마", keyword: "office building", commentary: "기회는 평등하게 주어지는 것처럼 보이지만, 그것을 잡기 위한 자격과 노력이 필요함을 시사합니다." },
    { text: "오늘, 당신의 하루는 어땠습니까? 아무리 힘든 하루였어도, 내일은 오늘보다 나을 겁니다.", author: "드라마 '응답하라 1988'", category: "드라마", keyword: "old alleyway", commentary: "힘든 시기를 보내는 모든 이에게 건네는 따뜻하고 소박한 위로의 메시지입니다." },
    { text: "우리에게 필요한 것은 아마도 열정이 아니라, 시작할 용기일지도 모른다.", author: "드라마 '스토브리그'", category: "드라마", keyword: "baseball stadium", commentary: "거창한 열정보다, 작은 것이라도 지금 당장 실행에 옮기는 용기가 변화를 만듭니다." },
    { text: "한 번 사는 인생, 뭐든 될 수 있잖아.", author: "드라마 '이태원 클라쓰'", category: "드라마", keyword: "seoul night", commentary: "어려운 환경 속에서도 자신의 소신을 굽히지 않고 꿈을 향해 나아가는 용기를 북돋아 줍니다." },
    { text: "영광의 순간을 위해, 기꺼이 어둠 속을 걷겠다.", author: "드라마 '더 글로리'", category: "드라마", keyword: "go board", commentary: "자신의 목표를 이루기 위해 어떤 고통과 희생도 감수하겠다는 처절한 의지를 보여줍니다." },

    // 투자/경제 (Investing/Economy)
    { text: "규칙 1: 절대로 돈을 잃지 마라. 규칙 2: 규칙 1을 절대로 잊지 마라.", author: "워런 버핏", category: "투자", keyword: "stock chart", commentary: "공격적인 수익 추구보다 리스크 관리와 원금 보존이 장기 투자의 핵심 원칙임을 강조합니다." },
    { text: "다른 사람들이 탐욕을 부릴 때 두려워하고, 다른 사람들이 두려워할 때 탐욕을 부려라.", author: "워런 버핏", category: "투자", keyword: "wall street", commentary: "대중의 심리와 반대로 행동하는 역발상 투자의 중요성을 역설합니다." },
    { text: "훌륭한 기업을 적당한 가격에 사는 것이, 적당한 기업을 훌륭한 가격에 사는 것보다 훨씬 낫다.", author: "워런 버핏", category: "투자", keyword: "magnifying glass", commentary: "단기적인 가격 할인보다 장기적인 기업의 본질적 가치(Quality)에 집중해야 함을 의미합니다." },
    { text: "인내는 복리의 핵심 요소다.", author: "찰리 멍거", category: "투자", keyword: "hourglass", commentary: "시간과 인내심이야말로 복리라는 마법을 극대화하는 가장 중요한 재료입니다." },
    { text: "자신이 무엇을 모르는지 아는 것이 지성의 특징이다.", author: "찰리 멍거", category: "투자", keyword: "library", commentary: "자신의 능력 범위(Circle of Competence)를 명확히 알고, 그 안에서만 행동하는 것의 중요성을 말합니다." },
    { text: "주식 시장은 인내심 없는 사람의 돈을 인내심 있는 사람에게 이동시키는 도구다.", author: "워런 버핏", category: "투자", keyword: "money", commentary: "단기적인 시장 변동성에 흔들리지 않고 장기적인 가치를 믿고 기다리는 것이 성공의 열쇠입니다." },
    { text: "위험은 자신이 무엇을 하고 있는지 모르는 것에서 온다.", author: "워런 버핏", category: "투자", keyword: "risk management", commentary: "깊은 이해 없는 투자는 도박에 불과합니다. 공부하고 이해한 범위 안에서만 투자해야 합니다." },
    { text: "복리는 세계 8번째 불가사의다. 이것을 이해하는 자는 돈을 벌고, 이해하지 못하는 자는 돈을 낸다.", author: "찰리 멍거", category: "투자", keyword: "compound interest", commentary: "시간과 재투자의 마법인 복리를 이해하고 활용하는 것이 부의 축적의 핵심 원리입니다." },

    // 사랑 (Love)
    { text: "사랑하는 것은 사랑받는 것보다 훨씬 더 행복하다.", author: "아리스토텔레스", category: "사랑", keyword: "hearts", commentary: "사랑받기를 원하기 전에, 먼저 베풀고 사랑하는 능동적인 자세가 더 큰 기쁨을 줍니다." },
    { text: "당신이 사랑하는 것을 하라, 그리고 사랑하는 사람 곁에 있어라. 그것이 전부다.", author: "제인 오스틴", category: "사랑", keyword: "couple walking", commentary: "삶에서 가장 중요한 두 가지는 자신이 열정을 쏟는 일과 함께할 사람임을 간결하게 말합니다." },
    { text: "사랑은 서로를 바라보는 것이 아니라, 함께 같은 방향을 바라보는 것이다.", author: "마르셀 프루스트", category: "사랑", keyword: "horizon together", commentary: "진정한 사랑은 상대에 대한 집착이 아니라, 같은 꿈과 가치를 향해 나아가는 동반자 관계입니다." },
    { text: "당신이 사랑하는 사람이 당신을 떠나더라도, 그 사랑이 당신 안에 새겨 놓은 것은 영원히 남는다.", author: "루미", category: "사랑", keyword: "rose", commentary: "이별의 아픔 속에서도 사랑의 경험 자체가 우리를 더 깊은 사람으로 성장시킨다는 위로입니다." },
    { text: "사랑이 없는 곳에 사랑을 심어라, 그러면 사랑을 거둘 것이다.", author: "달라이 라마", category: "사랑", keyword: "garden flowers", commentary: "사랑은 받는 것이 아니라 주는 것이며, 베푸는 만큼 되돌아온다는 진리를 말합니다." },
    { text: "나는 당신 없이도 살 수 있다. 다만 살고 싶지 않을 뿐이다.", author: "영화 '라라랜드'", category: "사랑", keyword: "city lights romance", commentary: "상대방이 삶의 의미이자 이유가 되는 사랑의 깊이를 절절하게 표현합니다." },
    { text: "사랑은 두 사람이 서로의 눈을 바라보며 이루는 것이 아니라, 함께 같은 것을 바라보며 이루는 것이다.", author: "빅토르 위고", category: "사랑", keyword: "lighthouse", commentary: "공통된 이상과 가치를 공유하는 사랑이야말로 시간을 이기는 진정한 사랑입니다." },
    { text: "사랑받는 것은 힘이고, 사랑하는 것은 용기다.", author: "루미", category: "사랑", keyword: "sunlight hands", commentary: "상처를 두려워하지 않고 먼저 마음을 여는 것, 그것이 사랑이 요구하는 진정한 용기입니다." },
    { text: "그대가 없을 때 나는 그대를 그리워하지만, 그대가 있을 때 나는 그대를 더욱 그리워한다.", author: "마크 저커버그", category: "사랑", keyword: "window rain", commentary: "상대방의 존재가 더 깊은 그리움을 만들어내는 사랑의 역설적인 아름다움을 표현합니다." },
    { text: "사랑은 맹목적이다. 그것은 연인들로 하여금 그들이 저지르는 어리석음을 보지 못하게 한다.", author: "윌리엄 셰익스피어", category: "사랑", keyword: "blindfolded", commentary: "사랑에 빠진 사람은 상대의 단점보다 아름다움을 먼저 보게 되는 인간의 본성을 묘사합니다." },
    { text: "사랑은 이해와 존중을 의미한다. 소유가 아니라.", author: "영화 '겨울왕국'", category: "사랑", keyword: "open hands", commentary: "집착과 통제가 아닌 상대를 있는 그대로 인정하는 것이 진정한 사랑의 자세입니다." },

    // 용기 (Courage)
    { text: "용기는 두려움이 없는 것이 아니다. 두려움보다 더 중요한 것이 있다고 판단하는 것이다.", author: "마야 안젤루", category: "용기", keyword: "cliff edge", commentary: "두려움을 느끼면서도 앞으로 나아가는 선택, 그것이 진정한 용기의 본질입니다." },
    { text: "최선을 다해 용감히 살아라. 왜냐하면 인생은 짧고 기회가 두 번 오지 않기 때문이다.", author: "나폴레옹 보나파르트", category: "용기", keyword: "battlefield dawn", commentary: "유한한 삶 앞에서 망설임보다는 과감한 도전이 더 가치있는 삶을 만든다는 격언입니다." },
    { text: "배가 항구에 있을 때는 안전하다. 그러나 그것이 배의 존재 이유가 아니다.", author: "존 A. 세드", category: "용기", keyword: "ship ocean", commentary: "안전한 현실에 안주하는 것은 자신의 진정한 가능성을 포기하는 것과 같습니다." },
    { text: "나는 두려웠지만 그래도 했다. 그것이 용기다.", author: "마야 안젤루", category: "용기", keyword: "lion", commentary: "겁이 없어서가 아니라, 두려움에도 불구하고 실행하는 것이 용기의 정의입니다." },
    { text: "어둠이 깊을수록 새벽이 가깝다.", author: "마틴 루터 킹 주니어", category: "용기", keyword: "dark before dawn", commentary: "가장 힘든 시간이 바로 변화와 희망의 문턱임을 잊지 말라는 강력한 위로의 메시지입니다." },
    { text: "용감한 자는 필요할 때 두려움도 느끼지만, 그것을 통제할 수 있는 사람이다.", author: "아리스토텔레스", category: "용기", keyword: "warrior", commentary: "두려움을 억누르는 것이 아니라 그것을 다스리며 행동하는 능력이 진정한 용기입니다." },
    { text: "도전하지 않으면 아무것도 이룰 수 없다.", author: "무하마드 알리", category: "용기", keyword: "boxing ring", commentary: "링 위에서나 삶에서나, 도전이 없으면 성취도 없다는 불변의 진리를 전달합니다." },
    { text: "한 번도 실수한 적 없는 사람은 한 번도 새로운 것을 시도하지 않은 사람이다.", author: "아인슈타인", category: "용기", keyword: "experiment lab", commentary: "실수는 새로운 시도의 증거이자, 성장의 필수적인 과정임을 역설합니다." },
    { text: "두려움은 정신을 죽이는 작은 죽음이다. 나는 두려움을 직면할 것이다.", author: "영화 '듄'", category: "용기", keyword: "desert storm", commentary: "두려움을 회피하지 않고 직시하는 것이 그것을 극복하는 유일한 방법입니다." },

    // 행복 (Happiness)
    { text: "행복은 미래에 있지 않다. 행복은 지금 이 순간에 있다.", author: "마르쿠스 아우렐리우스", category: "행복", keyword: "sunshine field", commentary: "언젠가를 기다리는 삶은 현재를 낭비하는 삶입니다. 지금 이 순간에 집중하세요." },
    { text: "행복해지기로 결심한 만큼 행복해질 수 있다.", author: "에이브러햄 링컨", category: "행복", keyword: "smile portrait", commentary: "행복은 외부 조건이 아닌 내면의 선택에서 비롯된다는 심리학적 진리를 담고 있습니다." },
    { text: "비교는 기쁨을 앗아가는 도둑이다.", author: "루이즈 메이 올컷", category: "행복", keyword: "own path", commentary: "다른 사람의 삶과 비교하는 순간 나만의 행복한 이야기는 흐릿해집니다." },
    { text: "진정한 행복은 내면에서 비롯된다. 당신 밖에서는 찾을 수 없다.", author: "오프라 윈프리", category: "행복", keyword: "inner peace meditation", commentary: "지위, 물질, 타인의 인정에서 행복을 구하는 것은 모래 위에 집을 짓는 것과 같습니다." },
    { text: "웃음은 영혼에 좋은 약이다.", author: "찰리 채플린", category: "행복", keyword: "laughter joy", commentary: "유머와 웃음은 삶의 무게를 덜어주고, 세상을 더 살기 좋게 만드는 가장 쉬운 처방입니다." },
    { text: "지금 가진 것에 감사하는 사람이 더 많은 것을 얻는다.", author: "오프라 윈프리", category: "행복", keyword: "gratitude journal", commentary: "감사하는 마음은 더 많은 기쁨을 끌어들이는 에너지이며, 행복의 선순환을 만듭니다." },
    { text: "행복은 목적지가 아니라 여정이다.", author: "랄프 왈도 에머슨", category: "행복", keyword: "winding road", commentary: "행복은 어떤 목표를 달성했을 때 얻는 것이 아니라, 삶을 살아가는 과정 자체에 있습니다." },
    { text: "지금 이 순간, 당신이 가진 것에 집중하라.", author: "드라마 '나의 해방일지'", category: "행복", keyword: "simple life", commentary: "바쁜 일상 속에서 잊기 쉬운 현재의 소소한 기쁨과 평온함에 집중하도록 이끕니다." },
    { text: "당신의 꿈을 살면서 행복할 수는 없나요? 저는 그렇게 살고 있습니다.", author: "BTS", category: "행복", keyword: "stage spotlight", commentary: "자신이 원하는 삶을 향해 나아가는 것 자체가 행복임을 BTS의 여정이 보여줍니다." },

    // 리더십 (Leadership)
    { text: "리더가 되는 최선의 방법은 섬기는 자가 되는 것이다.", author: "마틴 루터 킹 주니어", category: "리더십", keyword: "hands helping", commentary: "진정한 리더는 군림하는 사람이 아니라, 팀원들을 위해 헌신하고 장애물을 제거하는 사람입니다." },
    { text: "당신이 하는 일은 무엇이든 최선을 다해서 하라.", author: "마야 안젤루", category: "리더십", keyword: "excellence craftsmanship", commentary: "큰 일이든 작은 일이든 매사에 최선을 다하는 자세가 위대한 리더의 기반입니다." },
    { text: "사람들이 무엇을 하는지보다 왜 하는지에 주목해야 위대한 리더가 될 수 있다.", author: "피터 드러커", category: "리더십", keyword: "vision board", commentary: "행동의 동기와 목적을 이해하는 것이 사람을 이끄는 리더의 핵심 역량입니다." },
    { text: "최고의 리더는 가장 많이 배우는 사람이다.", author: "리처드 브랜슨", category: "리더십", keyword: "open book learning", commentary: "변화하는 세상에서 지속적인 학습과 성장 없이는 진정한 리더십을 유지할 수 없습니다." },
    { text: "위대한 리더는 자신의 이익보다 팀의 이익을 먼저 생각한다.", author: "넬슨 만델라", category: "리더십", keyword: "team together", commentary: "자기희생과 팀을 위한 헌신이 구성원들의 자발적인 따름을 이끄는 진정한 리더십입니다." },
    { text: "혼자 가면 빨리 가고, 함께 가면 멀리 간다.", author: "넬슨 만델라", category: "리더십", keyword: "group journey", commentary: "개인의 속도보다 팀의 지속가능한 성장이 더 멀리, 더 크게 나아갈 수 있게 합니다." },
    { text: "진정한 리더십은 직함에서 나오지 않는다. 행동에서 나온다.", author: "오프라 윈프리", category: "리더십", keyword: "action leadership", commentary: "리더라는 타이틀이 아니라 매일의 결정과 행동이 당신을 진정한 리더로 만들어 줍니다." },
    { text: "세상에서 가장 어려운 일은 사람들의 마음을 움직이는 일이다.", author: "드라마 '미생'", category: "리더십", keyword: "inspire crowd", commentary: "숫자와 논리가 아니라 사람의 감정과 가치에 호소할 때 진정한 변화가 시작됩니다." },
    { text: "당신이 무엇을 하고 있는지가 아니라, 왜 하고 있는지가 사람들을 이끈다.", author: "손정의", category: "리더십", keyword: "purpose driven", commentary: "명확한 목적의식(Why)이 사람들의 열정과 헌신을 이끌어내는 가장 강력한 리더십 도구입니다." },

    // 창의성 (Creativity)
    { text: "창의성은 연결하는 것이다.", author: "스티브 잡스", category: "창의성", keyword: "connecting dots", commentary: "전혀 관계없어 보이는 분야의 지식과 경험을 연결하는 능력에서 혁신이 탄생합니다." },
    { text: "규칙을 알아야 그것을 현명하게 깰 수 있다.", author: "달라이 라마", category: "창의성", keyword: "breaking rules", commentary: "기존의 경계를 넘기 위해서는 먼저 그 경계가 어디에 있는지 정확히 알아야 합니다." },
    { text: "상상력은 지식보다 더 중요하다.", author: "아인슈타인", category: "창의성", keyword: "imagination clouds", commentary: "지식은 현재 아는 것의 범위이지만, 상상력은 아직 모르는 모든 가능성을 포함합니다." },
    { text: "예술은 당신이 무엇을 느끼는지를 보여준다.", author: "레오나르도 다빈치", category: "창의성", keyword: "painting canvas", commentary: "모든 창의적 작업의 본질은 내면의 감정과 진실을 형태로 표현하는 것입니다." },
    { text: "당신 안에 있는 예술가를 죽이지 마라. 그것이 당신이 가진 가장 소중한 것이다.", author: "루미", category: "창의성", keyword: "artist studio", commentary: "사회의 기대와 현실의 압박 속에서도 창의적인 내면의 목소리를 잃지 말라는 격려입니다." },
    { text: "창의성이란 틀에 박힌 생각에서 벗어나는 것이 아니라, 그 틀 자체가 없는 것이다.", author: "리드 호프먼", category: "창의성", keyword: "outside the box", commentary: "제약 없이 생각하는 훈련이야말로 진정한 혁신과 창의성의 토대입니다." },
    { text: "모든 아이는 예술가다. 어른이 되어서도 예술가로 남는 것이 문제다.", author: "파블로 피카소", category: "창의성", keyword: "child drawing", commentary: "어른이 되면서 잃어버리는 자유로운 상상력과 두려움 없는 표현이야말로 창의성의 핵심입니다." },

    // 변화 (Change)
    { text: "당신이 보고 싶은 세상의 변화가 되어라.", author: "마하트마 간디", category: "변화", keyword: "butterfly metamorphosis", commentary: "세상을 바꾸려면 먼저 자신 안에서 그 변화를 시작해야 합니다. 모든 혁명은 내면에서 시작됩니다." },
    { text: "변화가 힘든 것은 시작할 때뿐이다. 중간도 힘들고, 끝도 힘들다.", author: "마야 안젤루", category: "변화", keyword: "transformation road", commentary: "변화는 결코 쉽지 않습니다. 그러나 그 어려움을 알고 시작하는 것이 지혜롭습니다." },
    { text: "어제와 똑같은 행동을 반복하면서 다른 결과를 기대하는 것은 미친 짓이다.", author: "아인슈타인", category: "변화", keyword: "breaking cycle", commentary: "변화를 원한다면 먼저 자신의 행동을 바꾸어야 한다는 명료한 진리입니다." },
    { text: "변화를 두려워하지 마라. 변하지 않는 것이야말로 더 두려운 것이다.", author: "잭 마", category: "변화", keyword: "evolving world", commentary: "빠르게 변하는 세상에서 현상 유지는 퇴보를 의미할 수 있습니다." },
    { text: "강이 흐르지 않으면 연못이 된다.", author: "노자", category: "변화", keyword: "flowing river", commentary: "끊임없이 움직이고 변화하는 것이 삶과 자연의 본질임을 비유로 표현합니다." },
    { text: "첫 발을 내딛어라. 계단 전체를 볼 필요는 없다.", author: "마틴 루터 킹 주니어", category: "변화", keyword: "first step staircase", commentary: "변화는 전체 그림이 보이지 않아도 지금 당장 내딛는 작은 한 걸음에서 시작됩니다." },
    { text: "위기는 기회를 품고 있다.", author: "알베르 카뮈", category: "변화", keyword: "storm clearing", commentary: "모든 위기 속에는 기존 방식을 뛰어넘을 수 있는 변화의 씨앗이 담겨 있습니다." },
    { text: "세상은 당신이 변화를 일으키기에 너무 넓거나 크지 않다.", author: "BTS", category: "변화", keyword: "world map", commentary: "출신이나 배경에 관계없이 누구든 자신의 방식으로 세상을 변화시킬 수 있다는 격려입니다." },

    // 꿈 (Dreams)
    { text: "크게 생각하라. 당신의 꿈은 당신이 생각하는 것보다 훨씬 더 현실에 가깝다.", author: "손정의", category: "꿈", keyword: "stars dreaming", commentary: "꿈의 크기가 결국 성취의 크기를 결정합니다. 한계를 스스로 정하지 마세요." },
    { text: "나에게는 꿈이 있습니다.", author: "마틴 루터 킹 주니어", category: "꿈", keyword: "dream speech", commentary: "어둠 속에서도 꿈을 포기하지 않는 믿음이 역사를 바꾸고 세상을 변화시킬 수 있습니다." },
    { text: "당신이 꿈꿀 수 있다면, 당신은 그것을 이룰 수 있다.", author: "월트 디즈니", category: "꿈", keyword: "magic castle", commentary: "상상력은 현실 창조의 첫 번째 단계입니다. 꿈꾸는 것 자체가 이미 가능성의 시작입니다." },
    { text: "미래는 자신의 꿈의 아름다움을 믿는 자들의 것이다.", author: "엘레오노라 루즈벨트", category: "꿈", keyword: "future horizon", commentary: "스스로의 비전을 신뢰하고 그것을 향해 나아가는 자에게 미래가 열립니다." },
    { text: "별들을 향해 쏘아라. 달에도 못 미치면, 하늘 위에 있게 된다.", author: "레스 브라운", category: "꿈", keyword: "rocket launch", commentary: "높은 목표를 갖는 것만으로도 보통의 목표를 넘어서는 결과를 만들어낼 수 있습니다." },
    { text: "꿈꾸는 자가 세상을 바꾼다.", author: "영화 '라라랜드'", category: "꿈", keyword: "dreamers stars", commentary: "현실주의자들이 불가능하다고 하는 것을 꿈꾸는 자들이 결국 해냈습니다." },
    { text: "이루어질 꿈은 이루어지길 기다리지 않는다. 직접 만들어가는 것이다.", author: "잭 마", category: "꿈", keyword: "building future", commentary: "꿈은 수동적으로 기다리는 것이 아니라, 능동적으로 만들어 나가는 과정입니다." },
    { text: "포기한 꿈은 죽은 것이 아니다. 그것은 잠들어 있을 뿐이다.", author: "마야 안젤루", category: "꿈", keyword: "sleeping dream awakening", commentary: "어떤 이유로 꿈을 미루었더라도, 언제든 다시 깨울 수 있다는 희망의 메시지입니다." },

    // 시간 (Time)
    { text: "잃어버린 시간은 결코 되찾을 수 없다.", author: "세네카", category: "시간", keyword: "hourglass sand", commentary: "시간은 우리가 가진 유일하게 회수 불가능한 자원입니다. 낭비하지 마십시오." },
    { text: "지금 이 순간은 언제나 충분하다.", author: "헨리 데이비드 소로", category: "시간", keyword: "present moment", commentary: "과거와 미래에 사로잡히지 않고 지금 이 순간의 완전함을 인식하는 것이 행복의 열쇠입니다." },
    { text: "시간을 낭비하지 마라. 그것이 삶을 만드는 재료다.", author: "벤저민 프랭클린", category: "시간", keyword: "clock face", commentary: "시간 관리는 곧 삶 관리입니다. 어디에 시간을 쓰는가가 어떤 사람이 되는가를 결정합니다." },
    { text: "과거는 변하지 않는다. 미래는 아직 오지 않았다. 당신이 살 수 있는 것은 오직 현재뿐이다.", author: "마르쿠스 아우렐리우스", category: "시간", keyword: "now present", commentary: "지나간 것에 대한 후회와 다가올 것에 대한 불안 대신, 지금 이 순간에 집중해야 합니다." },
    { text: "당신이 좋아하는 일을 하라. 그러면 평생 하루도 일한 것 같지 않을 것이다.", author: "공자", category: "시간", keyword: "joyful work", commentary: "열정을 직업으로 만들면 시간의 흐름이 다르게 느껴집니다. 그것이 진정한 소명입니다." },
    { text: "지금이 최선이다. 어제와 내일 사이, 지금이 가장 빛나는 순간이다.", author: "드라마 '갯마을 차차차'", category: "시간", keyword: "golden sunset", commentary: "평범한 오늘의 소중함을 깨닫고 현재의 아름다움에 감사하도록 이끄는 메시지입니다." },
    { text: "우리는 모두 같은 하루 24시간을 가지고 있다. 차이는 그것을 어떻게 쓰는가다.", author: "오프라 윈프리", category: "시간", keyword: "daily schedule", commentary: "공평하게 주어진 시간을 어떻게 배분하고 투자하는가가 삶의 질을 결정합니다." },
    { text: "중요한 것과 급한 것을 구분하라. 중요한 것에 먼저 집중하라.", author: "피터 드러커", category: "시간", keyword: "priorities matrix", commentary: "효율적인 시간 관리의 핵심은 긴급하지 않지만 중요한 일에 선제적으로 투자하는 것입니다." },

    // 책 (Books)
    { text: "당신이 읽는 책들이 당신을 만든다.", author: "랄프 왈도 에머슨", category: "책", keyword: "stacked books", commentary: "독서는 단순한 정보 습득이 아니라, 당신의 사고방식과 세계관 자체를 형성하는 과정입니다." },
    { text: "책은 인생에 있어 충실한 친구요, 가장 훌륭한 스승이다.", author: "헨리 데이비드 소로", category: "책", keyword: "cozy reading", commentary: "언제나 곁에 있으며 언제나 배움을 주는 책은 인생 최고의 동반자입니다." },
    { text: "읽기 어려운 책을 읽는 사람이 보기 어려운 길을 간다.", author: "표도르 도스토옙스키", category: "책", keyword: "old library", commentary: "도전적인 책을 읽는 습관이 더 넓은 사고와 더 깊은 통찰력을 만들어냅니다." },
    { text: "독서는 다른 사람의 마음으로 생각하는 법을 배우는 것이다.", author: "올더스 헉슬리", category: "책", keyword: "open book pages", commentary: "책을 통해 다양한 관점과 경험을 흡수하는 것이 공감과 창의성의 원천입니다." },
    { text: "세상에서 가장 작은 교실은 책 한 권이다.", author: "레프 톨스토이", category: "책", keyword: "tiny book world", commentary: "한 권의 책이 담고 있는 지혜와 세계관은 그 어떤 교육보다도 광대할 수 있습니다." },
    { text: "많이 읽어라. 그것이 당신의 언어와 생각을 풍성하게 한다.", author: "어니스트 헤밍웨이", category: "책", keyword: "words writing", commentary: "독서는 어휘력만이 아니라 사고의 깊이와 표현의 아름다움을 키워주는 최고의 훈련입니다." },
    { text: "오늘의 독자가 내일의 리더다.", author: "마가렛 풀러", category: "책", keyword: "reader leader", commentary: "꾸준히 책을 읽는 사람은 더 넓은 시야와 통찰로 미래를 이끌 역량을 키웁니다." },
    { text: "책은 당신이 경험할 수 없는 수천 개의 삶을 선물한다.", author: "조지 R.R. 마틴", category: "책", keyword: "thousand lives", commentary: "한 번의 삶으로는 모자란 경험의 지평을 독서를 통해 무한히 확장할 수 있습니다." },

    // 성공 (Success) - 추가
    { text: "성공의 비밀은 목적의 일관성이다.", author: "벤저민 디즈레일리", category: "성공", keyword: "steady compass", commentary: "방향이 흔들리지 않는 것, 하나의 목표를 향해 꾸준히 나아가는 것이 성공의 핵심입니다." },
    { text: "먼저 생각하고, 나중에 행동하라. 하지만 너무 오래 생각만 하지는 마라.", author: "피터 드러커", category: "성공", keyword: "thinking acting", commentary: "철저한 준비와 분석이 필요하지만, 결국 실행하지 않으면 아무것도 이루어지지 않습니다." },
    { text: "성공은 진행 중인 사건이지, 도착지가 아니다.", author: "오프라 윈프리", category: "성공", keyword: "journey road", commentary: "성공이라는 최종 지점에 집착하는 것보다, 매일의 성장과 전진에 집중하는 것이 지혜롭습니다." },
    { text: "1%의 영감과 99%의 노력이 성공을 만든다.", author: "토마스 에디슨", category: "성공", keyword: "hard work grind", commentary: "창의적인 아이디어보다는 그것을 현실로 만드는 지속적인 노력이 훨씬 더 중요합니다." },
    { text: "기회는 특별한 형태로 오지 않는다. 준비된 자만이 알아본다.", author: "루이 파스퇴르", category: "성공", keyword: "opportunity door", commentary: "행운이란 준비와 기회가 만나는 지점입니다. 기회는 준비된 사람에게 먼저 보입니다." },

    // 지혜 (Wisdom) - 추가
    { text: "당신이 아는 것을 알고, 모르는 것은 모른다고 하는 것, 그것이 곧 앎이다.", author: "공자", category: "지혜", keyword: "knowing not knowing", commentary: "자신의 무지를 인정하는 것이 진정한 배움의 시작입니다. 가장 위험한 것은 모르면서 아는 척하는 것입니다." },
    { text: "현명한 사람은 자신이 말한 것에 대해 생각하고, 어리석은 사람은 자신이 말할 것에 대해 생각한다.", author: "하인리히 하이네", category: "지혜", keyword: "thoughtful speech", commentary: "말하기 전 먼저 생각하는 습관이 후회 없는 관계와 결정을 만들어냅니다." },
    { text: "경험은 가장 혹독한 스승이다. 먼저 시험을 주고, 나중에 교훈을 가르친다.", author: "오스카 와일드", category: "지혜", keyword: "hard lessons", commentary: "삶의 경험이 주는 교훈은 때로는 쓰라리지만, 그것이 가장 깊이 새겨지는 지혜입니다." },
    { text: "지혜는 진리를 알고, 아름다움을 느끼고, 선을 행하는 능력이다.", author: "임마누엘 칸트", category: "지혜", keyword: "wisdom light", commentary: "지식의 습득을 넘어 삶에서 좋은 것을 판단하고 실행하는 능력이 진정한 지혜입니다." },

    // 인생 (Life) - 추가
    { text: "살아있다는 것은 경이로운 일이다.", author: "알베르 카뮈", category: "인생", keyword: "sunrise alive", commentary: "무의미하게 느껴지는 일상 속에서도 존재 자체의 경이로움을 발견하는 것이 진정한 삶입니다." },
    { text: "인생에서 중요한 것은 얼마나 오래 사느냐가 아니라 얼마나 깊이 사느냐다.", author: "랄프 왈도 에머슨", category: "인생", keyword: "deep life", commentary: "긴 수명보다 지금 이 순간을 충만하게 살아가는 깊이와 강도가 더 소중합니다." },
    { text: "우리는 살아야 할 삶을 살지 않고, 살 수 있는 삶을 살고 있다.", author: "빅토르 프랭클", category: "인생", keyword: "authentic life", commentary: "두려움과 타협이 아닌 자신이 진정으로 원하는 삶을 향해 나아가야 합니다." },
    { text: "삶에서 가장 후회하는 것은 저지른 행동이 아니라, 하지 않은 행동이다.", author: "마크 트웨인", category: "인생", keyword: "regret choices", commentary: "망설이다 놓친 기회, 두려워서 하지 못한 도전이 인생 말미에 더 크게 후회로 남습니다." },
    { text: "당신의 시간은 한정적이다. 다른 사람의 삶을 살면서 낭비하지 마라.", author: "스티브 잡스", category: "인생", keyword: "authentic self", commentary: "남의 기준과 기대에 맞춰 살기보다, 자신의 가치와 목소리에 따라 사는 삶이 진정한 삶입니다." },

    // 드라마 - 추가
    { text: "살아있는 자는 살아야 한다.", author: "드라마 '무브 투 헤븐'", category: "드라마", keyword: "living on", commentary: "남겨진 사람들의 이야기를 통해, 살아있는 우리가 어떻게 삶에 최선을 다해야 하는지를 말합니다." },

    // 영화 - 추가
    { text: "우주에서 두려운 것은 냉기가 아니라, 우리가 혼자라는 것이다.", author: "영화 '그래비티'", category: "영화", keyword: "space alone", commentary: "아무리 혹독한 환경도 홀로라는 고립감만큼 무서운 것은 없습니다. 연결과 유대의 소중함을 전합니다." },
    { text: "누군가 기억하는 한, 당신은 사라지지 않는다.", author: "영화 '코코'", category: "영화", keyword: "memory candle", commentary: "사랑하는 사람을 기억하는 행위 자체가 그 사람을 살아있게 하는 가장 아름다운 방법입니다." },
    { text: "존재하는 것은 느끼는 것이다.", author: "영화 '소울'", category: "영화", keyword: "soul existence", commentary: "거대한 꿈이나 목적 이전에, 지금 이 순간 삶을 감각하고 느끼는 것 자체가 존재의 이유입니다." },
    { text: "당신이 말하고 싶지 않더라도, 그 침묵도 누군가에게는 답이 된다.", author: "영화 '오펜하이머'", category: "영화", keyword: "silence weight", commentary: "선택뿐만 아니라 침묵과 망설임도 결과를 만들어내는 하나의 행위임을 일깨웁니다." },

    // ======== 추가 명언 (확장 데이터셋) ========

    // 인생 (Life) - 확장
    { text: "나를 죽이지 못하는 것은 나를 더 강하게 만든다.", author: "프리드리히 니체", category: "인생", keyword: "strength overcome", commentary: "역경이 우리를 파괴하지 못할 때, 그것은 우리를 단련하고 더 강한 존재로 만들어줍니다." },
    { text: "삶은 대담한 모험이거나 아무것도 아니다.", author: "헬렌 켈러", category: "인생", keyword: "adventure bold", commentary: "시각과 청각을 잃었음에도 세상을 사랑한 헬렌 켈러의 삶에 대한 열정적인 선언입니다." },
    { text: "같은 강물에 두 번 발을 담글 수 없다.", author: "헤라클레이토스", category: "인생", keyword: "river flowing change", commentary: "강물은 끊임없이 흐르듯, 우리의 삶도 매 순간 변하고 있습니다. 변화가 삶의 본질입니다." },
    { text: "네가 무언가를 간절히 원할 때, 온 우주가 그것을 이루도록 도와준다.", author: "파울로 코엘료", category: "인생", keyword: "universe desire heart", commentary: "'연금술사'에서 코엘료가 전하는 핵심 메시지. 진정한 욕망을 갖는 순간 세상이 움직입니다." },
    { text: "우리는 우리의 선택이다.", author: "장 폴 사르트르", category: "인생", keyword: "choice identity self", commentary: "실존주의 철학의 핵심. 우리는 선택하는 존재이며, 그 선택들의 총합이 우리 자신입니다." },
    { text: "시작은 가장 중요한 부분이다.", author: "플라톤", category: "인생", keyword: "beginning start important", commentary: "어떤 일이든 첫걸음이 가장 중요합니다. 시작하지 않으면 아무것도 이루어지지 않습니다." },
    { text: "침묵하라. 아니면 침묵보다 더 가치 있는 말을 하라.", author: "피타고라스", category: "인생", keyword: "silence words value", commentary: "말의 무게를 알고 신중하게 발언하는 것이 지혜로운 삶의 기본입니다." },
    { text: "우리 모두는 별의 먼지로 만들어졌다.", author: "칼 세이건", category: "인생", keyword: "stars universe cosmic", commentary: "우리 몸을 구성하는 원소들은 별의 폭발에서 왔습니다. 우리는 우주의 일부입니다." },
    { text: "성공이 행복의 열쇠가 아니다. 행복이 성공의 열쇠다.", author: "알베르트 슈바이처", category: "인생", keyword: "happiness key success", commentary: "진정한 행복이 먼저 있어야 진정한 성공이 따라옵니다. 순서를 바꾸지 마세요." },
    { text: "삶은 앞으로만 살 수 있지만, 오직 뒤를 돌아보아야만 이해할 수 있다.", author: "쇠렌 키르케고르", category: "인생", keyword: "life forward understand backward", commentary: "삶은 미래를 향해 나아가면서도 과거의 경험으로 그 의미를 발견하는 과정입니다." },
    { text: "세상에서 가장 아름다운 것은 눈에 보이지도 손에 잡히지도 않는다. 오직 가슴으로만 느낄 수 있다.", author: "헬렌 켈러", category: "인생", keyword: "heart feel beautiful invisible", commentary: "진정한 아름다움은 외적인 것에 있지 않고 마음으로 느끼는 것에 있다는 깊은 통찰입니다." },
    { text: "사람은 고통을 선택할 수 없지만, 고통에 대한 태도는 선택할 수 있다.", author: "빅토르 프랭클", category: "인생", keyword: "pain attitude choice freedom", commentary: "홀로코스트 생존자 프랭클은 극한의 고통 속에서도 내면의 자유를 지킬 수 있다고 증명했습니다." },
    { text: "인간은 자유롭도록 선고받은 존재다.", author: "장 폴 사르트르", category: "인생", keyword: "freedom condemned human", commentary: "실존주의의 선언. 우리는 선택을 피할 수 없으며, 모든 순간 책임을 지고 선택해야 합니다." },
    { text: "아름다움이 세상을 구원할 것이다.", author: "표도르 도스토옙스키", category: "인생", keyword: "beauty salvation world spirit", commentary: "물질과 이성이 아닌 예술적이고 정신적인 아름다움이 인류를 구원할 힘을 가졌다는 믿음입니다." },
    { text: "나는 생각한다, 고로 나는 존재한다.", author: "르네 데카르트", category: "인생", keyword: "think exist cogito", commentary: "철학의 가장 유명한 명제. 생각하는 행위 자체가 존재의 증거라는 데카르트의 혁명적 통찰입니다." },
    { text: "완벽한 것을 기다리지 말고 지금 할 수 있는 것을 하라.", author: "나폴레옹 보나파르트", category: "인생", keyword: "perfect wait action now", commentary: "완벽한 조건은 오지 않습니다. 지금 이 순간 가진 것으로 시작하는 것이 지혜입니다." },
    { text: "인생은 우리에게 일어나는 일이 아니라, 우리가 그것을 어떻게 받아들이느냐다.", author: "마르쿠스 아우렐리우스", category: "인생", keyword: "perception reaction life attitude", commentary: "스토아 철학의 핵심. 상황을 통제할 수 없어도, 반응하는 방식은 선택할 수 있습니다." },
    { text: "한 사람의 죽음은 비극이지만, 백만 명의 죽음은 통계다.", author: "요제프 스탈린", category: "인생", keyword: "tragedy statistics human empathy", commentary: "규모가 커질수록 개별 인간의 고통에 무감각해지는 인간의 역설적 심리를 지적합니다." },
    { text: "바람이 부는 방향은 바꿀 수 없지만, 돛을 조정할 수는 있다.", author: "지미 딘", category: "인생", keyword: "wind sail adjust control", commentary: "통제할 수 없는 환경보다 그에 대한 우리의 대응 방식을 바꾸는 것이 지혜입니다." },
    { text: "좋은 판단은 경험에서 오고, 경험은 나쁜 판단에서 온다.", author: "마크 트웨인", category: "인생", keyword: "judgment experience mistakes learn", commentary: "실수와 실패를 통해서만 좋은 판단력이 길러집니다. 경험이야말로 최고의 스승입니다." },
    { text: "우리가 볼 수 없는 것을 상상할 수 없다면 우리는 그것을 만들 수 없다.", author: "칼 세이건", category: "인생", keyword: "imagination vision create", commentary: "먼저 마음속에서 그릴 수 있어야 현실에서 창조할 수 있습니다. 상상력은 창조의 출발점입니다." },
    { text: "당신이 어디에 있든, 당신은 거기에 있다.", author: "존 카밧진", category: "인생", keyword: "presence mindfulness here now", commentary: "마음챙김의 본질. 과거나 미래가 아닌 지금 이 순간 여기에 온전히 있는 것이 삶의 기술입니다." },
    { text: "진정한 여행은 새로운 풍경을 찾는 것이 아니라 새로운 눈을 갖는 것이다.", author: "마르셀 프루스트", category: "인생", keyword: "travel new eyes perspective", commentary: "장소가 아닌 시각이 바뀔 때 진정한 여행이 시작됩니다. 세상은 보는 방식에 달려 있습니다." },

    // 성공 (Success) - 확장
    { text: "성공은 우연이 아니다. 그것은 노력, 인내, 배움, 희생, 그리고 하는 일에 대한 사랑이다.", author: "펠레", category: "성공", keyword: "effort persistence love work", commentary: "축구 황제 펠레는 타고난 재능보다 헌신과 열정이 위대한 성취를 만든다고 말합니다." },
    { text: "지금 당신이 있는 곳에서 시작하라. 가진 것을 사용하라. 할 수 있는 것을 하라.", author: "아서 에쉬", category: "성공", keyword: "start now here resources action", commentary: "완벽한 조건을 기다리지 말고, 지금 이 순간의 자원으로 바로 시작하는 실행력이 중요합니다." },
    { text: "꾸준함은 재능보다 강하다.", author: "코비 브라이언트", category: "성공", keyword: "consistency talent mamba", commentary: "'맘바 멘탈리티'의 코비는 매일 새벽 4시에 훈련하며 재능이 아닌 습관으로 전설이 되었습니다." },
    { text: "남들이 잠잘 때 공부하고, 남들이 공부할 때 실천하라.", author: "세종대왕", category: "성공", keyword: "diligence study practice discipline", commentary: "한발 앞서 행동하고 더 깊이 생각하는 것이 경쟁에서 앞서가는 비결입니다." },
    { text: "내가 더 많이 연습할수록, 나는 더 운이 좋아진다.", author: "게리 플레이어", category: "성공", keyword: "practice luck effort golf", commentary: "운은 하늘에서 떨어지는 것이 아니라 끊임없는 준비와 노력이 만들어내는 것입니다." },
    { text: "배움을 멈추면 성장도 멈춘다. 성장이 멈추면 쇠퇴가 시작된다.", author: "잭 웰치", category: "성공", keyword: "learning growth decay stop", commentary: "GE를 이끈 잭 웰치는 지속적 학습을 성공적 리더십의 필수 조건으로 봤습니다." },
    { text: "위대한 성공에는 위대한 시련이 따른다.", author: "나폴레옹 힐", category: "성공", keyword: "great success trial challenge", commentary: "성공의 크기는 극복한 어려움의 크기와 비례합니다. 시련을 피하려 하지 마세요." },
    { text: "포기란 없다. 이 길이 아니면 다른 길을 찾는 것이다.", author: "박세리", category: "성공", keyword: "no give up another way", commentary: "한국 골프의 전설 박세리는 실패 앞에서 포기 대신 다른 가능성을 찾는 자세를 강조합니다." },
    { text: "오늘의 나는 어제의 내 선택이 만들었다.", author: "스티븐 코비", category: "성공", keyword: "choice yesterday today build", commentary: "'성공하는 사람들의 7가지 습관'의 저자. 오늘을 만드는 것은 과거의 선택과 습관들입니다." },
    { text: "사람들이 당신을 비웃는다면, 당신은 분명히 다른 무언가를 하고 있는 것이다.", author: "빌 게이츠", category: "성공", keyword: "different laugh innovate", commentary: "혁신은 언제나 처음에는 이해받지 못하고 조롱받습니다. 다름은 성공의 신호일 수 있습니다." },
    { text: "어렵다는 것은 할 수 있다는 뜻이다. 불가능하다는 것은 조금 더 시간이 걸린다는 뜻이다.", author: "단델리온 팻튼", category: "성공", keyword: "difficult possible time patience", commentary: "불가능처럼 보이는 일도 포기하지 않고 지속하면 결국 이루어집니다." },
    { text: "당신이 충분히 노력한다면, 무엇이든 이룰 수 있다.", author: "에이브러햄 링컨", category: "성공", keyword: "hard work anything achieve lincoln", commentary: "통나무집에서 미국 대통령이 된 링컨의 삶 자체가 이 말의 증거입니다." },
    { text: "성공하는 사람들은 어려운 일을 먼저 한다.", author: "브라이언 트레이시", category: "성공", keyword: "hard task first prioritize", commentary: "가장 중요하고 어려운 일을 미루지 않고 먼저 처리하는 '개구리 먹기' 전략의 핵심입니다." },
    { text: "성공은 기술이 아니라 습관이다.", author: "로빈 샤르마", category: "성공", keyword: "success habit routine daily", commentary: "'새벽 5시의 기적'의 저자. 매일의 작은 루틴이 쌓여 위대한 성취를 만들어냅니다." },
    { text: "실행이 모든 것을 이긴다.", author: "게리 바이너척", category: "성공", keyword: "execution beats everything action", commentary: "아이디어는 누구나 있지만, 실제로 실행에 옮기는 사람만이 결과를 만들어냅니다." },
    { text: "오늘 할 수 있는 일을 절대 내일로 미루지 마라.", author: "벤저민 프랭클린", category: "성공", keyword: "procrastination today tomorrow action", commentary: "미국 건국의 아버지 프랭클린의 시간 관리 철학. 지금 당장 할 수 있는 것을 실행하세요." },
    { text: "최고의 복수는 성공하는 것이다.", author: "프랭크 시나트라", category: "성공", keyword: "revenge success prove yourself", commentary: "자신을 무시하거나 의심했던 사람들에게 가장 강력한 대답은 실제로 성공하는 것입니다." },
    { text: "노력이 재능을 이긴다. 재능이 노력하지 않을 때는.", author: "팀 노팅엄", category: "성공", keyword: "effort beats talent lazy", commentary: "타고난 재능도 갈고닦지 않으면 소용없고, 꾸준한 노력은 부족한 재능을 보완합니다." },
    { text: "목표를 세우고 그것을 달성하기 위한 계획을 짜라. 다른 방법은 없다.", author: "얼 나이팅게일", category: "성공", keyword: "goal plan method success formula", commentary: "목표와 계획 없이 성공하는 것은 목적지 없이 길을 떠나는 것과 같습니다." },
    { text: "당신이 상상할 수 있는 것이라면, 이룰 수 있다.", author: "윌리엄 아서 워드", category: "성공", keyword: "imagine achieve dream reality", commentary: "상상력은 현실 창조의 첫 번째 단계입니다. 마음속에서 먼저 이루어져야 현실에서 가능합니다." },
    { text: "성공의 90%는 그냥 나타나는 것이다.", author: "우디 앨런", category: "성공", keyword: "showing up presence commitment", commentary: "포기하지 않고 계속 자리를 지키는 것, 그 꾸준함이 성공의 대부분을 차지합니다." },
    { text: "위험을 감수하지 않으면 아무것도 얻을 수 없다.", author: "마이클 조던", category: "성공", keyword: "risk gain take chance", commentary: "농구의 신 마이클 조던도 셀 수 없는 실패를 딛고 그 위대함을 이루었습니다." },

    // 지혜 (Wisdom) - 확장
    { text: "내가 아는 한 가지는, 내가 아무것도 모른다는 것이다.", author: "소크라테스", category: "지혜", keyword: "know nothing wisdom ignorance", commentary: "참된 지혜의 시작은 자신의 무지를 인정하는 것입니다. 이것이 소크라테스의 역설적 지혜입니다." },
    { text: "당신이 아는 것을 알고, 모르는 것은 모른다고 하는 것, 그것이 곧 앎이다.", author: "공자", category: "지혜", keyword: "knowing not knowing truth", commentary: "자신의 무지를 인정하는 것이 진정한 배움의 시작입니다. 모르면서 아는 척이 가장 위험합니다." },
    { text: "경험은 가장 혹독한 스승이다. 먼저 시험을 주고, 나중에 교훈을 가르친다.", author: "오스카 와일드", category: "지혜", keyword: "experience harsh teacher lesson test", commentary: "삶의 경험이 주는 교훈은 때로는 쓰라리지만, 그것이 가장 깊이 새겨지는 지혜입니다." },
    { text: "지혜로운 사람은 말하기 전에 생각하고, 어리석은 사람은 생각하기 전에 말한다.", author: "하인리히 하이네", category: "지혜", keyword: "think before speak wise foolish", commentary: "말하기 전 먼저 생각하는 습관이 후회 없는 관계와 결정을 만들어냅니다." },
    { text: "가장 어두운 밤도 끝이 있고, 해는 반드시 뜬다.", author: "빅토르 위고", category: "지혜", keyword: "dark night end sunrise hope", commentary: "아무리 힘든 상황도 영원하지 않습니다. 끝이 있다는 믿음이 고통을 견디게 합니다." },
    { text: "다른 사람의 말을 듣는 것은 당신이 할 수 있는 가장 관대한 일이다.", author: "브레네 브라운", category: "지혜", keyword: "listen generous connection empathy", commentary: "진심으로 듣는 행위 자체가 상대에게 존중과 사랑을 전달하는 가장 강력한 방법입니다." },
    { text: "의심하는 것을 두려워하지 마라. 의심은 지혜의 시작이다.", author: "르네 데카르트", category: "지혜", keyword: "doubt fear wisdom start question", commentary: "비판적 사고의 출발점인 의심은 지식을 검증하고 진리에 더 가까이 가는 도구입니다." },
    { text: "말은 은이고 침묵은 금이다.", author: "토마스 칼라일", category: "지혜", keyword: "silence gold words silver", commentary: "신중한 침묵이 때로는 어떤 말보다 더 큰 지혜와 힘을 발휘합니다." },
    { text: "좋은 판단은 경험에서 나오고, 경험은 나쁜 판단에서 나온다.", author: "마크 트웨인", category: "지혜", keyword: "judgment experience mistakes good", commentary: "실수와 실패를 통해서만 좋은 판단력이 길러집니다. 경험이야말로 최고의 스승입니다." },
    { text: "현명한 사람은 기회를 기다리지 않고, 기회를 만든다.", author: "프랜시스 베이컨", category: "지혜", keyword: "opportunity create wise wait", commentary: "환경에 수동적으로 반응하는 것이 아니라 능동적으로 상황을 만들어가는 것이 지혜입니다." },
    { text: "배운 것을 잊지 않는 것보다 배우지 않은 것을 깨닫는 것이 더 중요하다.", author: "알베르트 아인슈타인", category: "지혜", keyword: "unlearn learn new wisdom", commentary: "변화하는 세상에서 기존 지식을 내려놓고 새로운 것을 받아들이는 능력이 더 중요합니다." },
    { text: "모든 것을 알고 싶어 하는 사람은 아무것도 알지 못한다.", author: "베르나르 드 클레르보", category: "지혜", keyword: "everything nothing focus depth", commentary: "깊이 있는 한 가지를 아는 것이 얕게 많은 것을 아는 것보다 훨씬 가치 있습니다." },
    { text: "세상에서 가장 중요한 것은 자신을 이해하는 것이다.", author: "테렌티우스", category: "지혜", keyword: "understand yourself self knowledge", commentary: "자기 이해가 없으면 세상을 이해할 수 없습니다. 내면 탐구가 모든 지혜의 기반입니다." },
    { text: "지식은 힘이다.", author: "프랜시스 베이컨", category: "지혜", keyword: "knowledge power information", commentary: "정보와 이해가 세상을 변화시키는 힘을 가집니다. 배움은 가장 강력한 도구입니다." },
    { text: "가르치는 것은 두 번 배우는 것이다.", author: "조셉 주베르", category: "지혜", keyword: "teach learn twice understand", commentary: "다른 사람에게 설명하는 과정에서 우리 자신의 이해가 더 깊어집니다." },
    { text: "행복은 덕에 있으며, 덕은 지식에 있다.", author: "소크라테스", category: "지혜", keyword: "happiness virtue knowledge", commentary: "소크라테스는 진정한 행복은 윤리적 삶에서 오며, 그 삶은 앎에서 시작된다고 봤습니다." },
    { text: "인내는 쓰다. 그러나 그 열매는 달다.", author: "장 자크 루소", category: "지혜", keyword: "patience bitter sweet fruit", commentary: "지금의 고통과 인내가 나중에 풍성한 결실로 돌아온다는 지혜입니다." },
    { text: "자신을 극복하는 것이 가장 위대한 승리다.", author: "플라톤", category: "지혜", keyword: "overcome self greatest victory", commentary: "외부의 적을 이기는 것보다 내면의 나약함과 욕망을 다스리는 것이 더 어렵고 위대합니다." },

    // 사랑 (Love) - 확장
    { text: "사랑은 행동이다. 감정이 아니라.", author: "벨 훅스", category: "사랑", keyword: "love action not feeling", commentary: "사랑은 기분이 아니라 의지적인 선택과 실천입니다. 매일 사랑을 표현하고 행동하세요." },
    { text: "진정한 사랑은 두 사람이 서로 없어서는 안 되는 사이가 아니라, 서로를 더 나은 사람으로 만드는 사이다.", author: "니코 알보", category: "사랑", keyword: "true love better person grow", commentary: "건강한 사랑은 서로에 대한 의존이 아니라 서로를 성장시키는 관계입니다." },
    { text: "사랑은 두 사람이 서로를 마주 보는 것이 아니라 같은 방향을 함께 바라보는 것이다.", author: "생텍쥐페리", category: "사랑", keyword: "same direction together love", commentary: "'어린 왕자'의 저자가 말하는 사랑. 공통된 꿈과 가치를 향해 함께 나아가는 것입니다." },
    { text: "나는 당신 없이도 살 수 있다. 다만 살고 싶지 않을 뿐이다.", author: "영화 '이유 없는 반항'", category: "사랑", keyword: "live without you love need", commentary: "상대방이 삶의 의미이자 이유가 되는 사랑의 깊이를 표현합니다." },
    { text: "사랑받고 싶다면 먼저 사랑하고 사랑스러운 사람이 되어라.", author: "벤저민 프랭클린", category: "사랑", keyword: "loveable first give love", commentary: "사랑받기를 원하기 전에 먼저 베풀고 사랑스러운 사람이 되는 것이 순서입니다." },
    { text: "오직 한 번만 사랑하지 않으면 진정한 사랑이 아니다.", author: "알프레드 드 뮈세", category: "사랑", keyword: "one true love once pure", commentary: "사랑의 순수함과 진정성. 진정한 사랑은 흔들리지 않는 하나의 신념과 같습니다." },
    { text: "사랑하는 사람의 행복이 나의 행복보다 우선이 될 때, 비로소 사랑이라 부를 수 있다.", author: "에리히 프롬", category: "사랑", keyword: "other happiness first sacrifice love", commentary: "'사랑의 기술'의 저자 프롬은 진정한 사랑을 상대의 성장과 행복을 위한 헌신으로 정의합니다." },
    { text: "사랑에는 이유가 없다. 이유가 있다면 그것은 사랑이 아니다.", author: "빅토르 위고", category: "사랑", keyword: "love no reason unconditional", commentary: "조건 없는 사랑이야말로 진정한 사랑입니다. 이유와 조건을 따지면 그것은 거래가 됩니다." },
    { text: "당신이 사랑하는 사람을 자유롭게 하라. 돌아온다면 당신의 것이고, 돌아오지 않는다면 처음부터 당신의 것이 아니었다.", author: "리처드 바크", category: "사랑", keyword: "love set free return yours", commentary: "집착이 아닌 자유를 주는 것이 진정한 사랑의 증표입니다." },
    { text: "사랑이 없는 집은 집이 아니다. 단지 방의 집합일 뿐이다.", author: "매들린 캐머런", category: "사랑", keyword: "home love rooms together", commentary: "공간을 의미 있는 곳으로 만드는 것은 그곳을 채우는 사랑입니다." },
    { text: "사랑하는 것만이 진정으로 사는 것이다.", author: "알베르트 아인슈타인", category: "사랑", keyword: "love truly live existence", commentary: "과학자 아인슈타인이 말한 삶의 본질. 사랑하는 존재와 경험이 삶을 의미 있게 만듭니다." },
    { text: "사랑은 가장 강한 힘이고, 그러면서도 가장 겸손한 힘이다.", author: "마하트마 간디", category: "사랑", keyword: "love strongest humble force power", commentary: "간디의 비폭력 철학의 핵심인 사랑. 가장 강하면서도 가장 부드러운 힘입니다." },

    // 용기 (Courage) - 확장
    { text: "한 번도 실수한 적 없는 사람은 한 번도 새로운 것을 시도하지 않은 사람이다.", author: "아인슈타인", category: "용기", keyword: "mistake try new attempt", commentary: "실수는 새로운 시도의 증거이자, 성장의 필수적인 과정임을 역설합니다." },
    { text: "당신이 두려워하는 일을 매일 하나씩 하라.", author: "엘리너 루스벨트", category: "용기", keyword: "fear daily overcome courage", commentary: "두려움에 맞서는 가장 효과적인 방법은 그것을 매일 조금씩 직면하는 것입니다." },
    { text: "사자는 먹잇감을 잡기 전에 두렵지 않은 척하지 않는다. 그냥 뛰어든다.", author: "드웨인 존슨", category: "용기", keyword: "lion jump courage action bold", commentary: "용기는 두려움을 없애는 것이 아니라 두려움과 함께 행동하는 것입니다." },
    { text: "가장 어두운 시간에도 빛을 켜는 것을 기억한다면, 우리는 버틸 수 있다.", author: "알버스 덤블도어 (J.K. 롤링)", category: "용기", keyword: "darkness light remember courage", commentary: "'해리 포터'의 지혜로운 교장이 전하는 메시지. 희망의 불씨를 지키는 것이 용기입니다." },
    { text: "나는 실패했다. 그리고 그것이 내가 성공한 이유다.", author: "마이클 조던", category: "용기", keyword: "failure reason success jordan", commentary: "9000개 이상의 슛을 놓쳤지만 포기하지 않은 조던의 이야기가 이 말의 증거입니다." },
    { text: "두려움은 항상 거짓말을 한다. 두려움이 말하는 대로 믿지 마라.", author: "에미 포헬러", category: "용기", keyword: "fear lies believe truth", commentary: "두려움이 속삭이는 '할 수 없다'는 말은 대부분 거짓입니다. 그 목소리를 의심하세요." },
    { text: "용기란 두려워하면서도 안장에 오르는 것이다.", author: "존 웨인", category: "용기", keyword: "courage afraid saddle mount", commentary: "서부 영화의 전설이 전하는 용기의 정의. 두려움을 안고도 행동하는 것입니다." },
    { text: "패배를 인정하는 것보다 결코 시도하지 않는 것이 더 큰 패배다.", author: "시어도어 루스벨트", category: "용기", keyword: "never try bigger defeat", commentary: "시도했다가 실패하는 것보다 시도조차 하지 않는 것이 훨씬 더 깊은 후회를 남깁니다." },
    { text: "그들이 당신을 쓰러뜨릴 수는 있다. 그러나 당신이 일어서는 것을 막을 수는 없다.", author: "마야 안젤루", category: "용기", keyword: "knock down rise stand up", commentary: "아무리 힘든 상황에서도 다시 일어서는 선택은 오직 자신만이 할 수 있습니다." },
    { text: "용기는 근육과 같다. 사용할수록 강해진다.", author: "루스 고든", category: "용기", keyword: "courage muscle strengthen use", commentary: "매일 작은 용기를 내는 연습이 쌓여 더 큰 용기를 낼 수 있는 힘을 기릅니다." },
    { text: "가장 용감한 행동은 혼자서 생각하고 큰 소리로 말하는 것이다.", author: "코코 샤넬", category: "용기", keyword: "brave alone think speak out", commentary: "다수의 의견에 따르지 않고 자신의 생각을 용기 있게 표현하는 것이 진정한 용기입니다." },
    { text: "인생에서 가장 무서운 것은 실패가 아니라 도전하지 않는 것이다.", author: "페이 던웨이", category: "용기", keyword: "scariest not failure not trying", commentary: "실패보다 시도조차 하지 않는 것이 진정 두려워해야 할 것입니다." },

    // 행복 (Happiness) - 확장
    { text: "행복의 비결은 더 많이 원하는 것이 아니라, 가진 것을 더 충분히 누리는 것이다.", author: "드니 디드로", category: "행복", keyword: "happiness secret enough enjoy", commentary: "끝없는 욕망 추구가 아닌 현재 가진 것에서 기쁨을 찾는 것이 진정한 행복의 길입니다." },
    { text: "행복한 사람은 많은 것을 가진 사람이 아니라 필요한 것만 가진 사람이다.", author: "알렉산더 대왕", category: "행복", keyword: "happy enough needs not more", commentary: "물질의 양이 아닌 필요와 욕망 사이의 균형에서 행복이 옵니다." },
    { text: "타인과 비교하는 순간 당신의 행복은 절반이 된다.", author: "테오도어 루스벨트", category: "행복", keyword: "compare other half happiness stolen", commentary: "비교는 상대적 결핍감을 만들어냅니다. 자신만의 기준으로 삶을 평가하세요." },
    { text: "작은 것에 감사하는 사람이 큰 것도 얻게 된다.", author: "오프라 윈프리", category: "행복", keyword: "grateful small big gratitude", commentary: "감사의 태도는 더 많은 기쁨을 끌어당깁니다. 작은 감사가 큰 풍요를 만듭니다." },
    { text: "지금 이 순간이 바로 내가 바라던 그 행복이었다.", author: "드라마 '나의 아저씨'", category: "행복", keyword: "this moment happiness realized present", commentary: "우리는 종종 현재의 행복을 나중에서야 깨닫습니다. 지금 이 순간을 소중히 여기세요." },
    { text: "행복은 목적지가 아니라 여행하는 방식이다.", author: "마거릿 리 런백", category: "행복", keyword: "happiness way travel journey method", commentary: "어딘가 도착해야 행복해지는 것이 아니라, 지금 이 순간 어떻게 살아가느냐가 행복입니다." },
    { text: "다른 사람을 행복하게 만드는 것이 당신 자신을 행복하게 만드는 가장 빠른 길이다.", author: "달라이 라마", category: "행복", keyword: "others happy fastest own happiness", commentary: "이타적인 행동이 역설적으로 자신에게 가장 큰 행복감을 줍니다." },
    { text: "행복은 인생의 의미이자 목적이고, 인간 존재의 궁극적인 목표다.", author: "아리스토텔레스", category: "행복", keyword: "happiness meaning purpose ultimate goal", commentary: "아리스토텔레스는 '에우다이모니아'(행복한 번영)를 인간 삶의 가장 높은 목적으로 봤습니다." },
    { text: "단순하게 살아라. 그것이 행복의 가장 빠른 길이다.", author: "헨리 데이비드 소로", category: "행복", keyword: "simple life happiness simplify", commentary: "소로는 월든 숲에서 단순한 삶이 가져다주는 깊은 기쁨을 직접 실험하고 증명했습니다." },
    { text: "행복은 무엇이 일어나느냐에 달린 것이 아니라 그것을 어떻게 받아들이느냐에 달렸다.", author: "마사 워싱턴", category: "행복", keyword: "happiness acceptance response event", commentary: "외부 사건이 아닌 내면의 반응이 행복을 결정합니다. 인식이 전부입니다." },
    { text: "당신이 좋아하는 것을 하라. 그러면 행복이 따라온다.", author: "마크 트웨인", category: "행복", keyword: "like do happiness follow passion", commentary: "자신이 열정을 느끼는 일을 할 때 자연스럽게 행복이 따라옵니다." },
    { text: "친구, 책, 자연, 그리고 웃음. 이것이 행복의 재료다.", author: "랄프 왈도 에머슨", category: "행복", keyword: "friends books nature laughter happiness", commentary: "물질이 아닌 관계, 배움, 자연과의 연결에서 진정한 행복의 재료를 찾을 수 있습니다." },

    // 리더십 (Leadership) - 확장
    { text: "리더는 길을 알고, 길을 걷고, 길을 보여준다.", author: "존 맥스웰", category: "리더십", keyword: "leader know walk show path", commentary: "말만 하는 지도자가 아닌 직접 실천하며 본을 보이는 것이 진정한 리더십입니다." },
    { text: "좋은 리더는 자신의 실수를 인정한다.", author: "브루스 리", category: "리더십", keyword: "admit mistake leader good honest", commentary: "실수를 인정하고 책임지는 모습이 오히려 신뢰와 존경을 이끌어냅니다." },
    { text: "사람들은 당신이 한 말을 잊을 것이다. 당신이 한 일도 잊을 것이다. 그러나 당신이 그들에게 느끼게 한 것은 절대 잊지 않을 것이다.", author: "마야 안젤루", category: "리더십", keyword: "forget words deeds feel remember", commentary: "리더십은 논리나 정책이 아닌 사람들의 마음을 어떻게 움직이느냐에 달려 있습니다." },
    { text: "가장 위대한 리더는 가장 많이 봉사하는 사람이다.", author: "리오 버스칼리아", category: "리더십", keyword: "greatest servant serve leader", commentary: "서번트 리더십의 핵심. 군림하는 것이 아니라 팀을 섬기는 것이 위대한 리더십입니다." },
    { text: "팀원들이 잘 될 때 나도 잘 된다.", author: "손흥민", category: "리더십", keyword: "team win together son heungmin", commentary: "한국 축구의 자존심 손흥민이 보여주는 팀 퍼스트 리더십 철학입니다." },
    { text: "훌륭한 리더는 팀원들의 강점을 최대화하고 약점을 최소화한다.", author: "드와이트 아이젠하워", category: "리더십", keyword: "maximize strength minimize weakness team", commentary: "모든 사람의 약점을 보완하려 하기보다 강점에 집중하는 것이 효과적 리더십입니다." },
    { text: "당신이 사람들에게 나아가야 할 방향을 알려줄 때, 그들이 실제로 어디로 가는지를 보라.", author: "스티브 잡스", category: "리더십", keyword: "direction observe people go", commentary: "리더의 비전이 팀원들에게 제대로 전달되고 실행되는지 지속적으로 확인해야 합니다." },
    { text: "리더십의 궁극적인 목표는 더 많은 리더를 만드는 것이다.", author: "랄프 네이더", category: "리더십", keyword: "leadership goal create more leaders", commentary: "진정한 리더는 추종자가 아닌 또 다른 리더를 키워내는 사람입니다." },
    { text: "리더는 희망의 판매자다.", author: "나폴레옹 보나파르트", category: "리더십", keyword: "leader hope seller inspire", commentary: "나폴레옹이 정의한 리더십의 본질. 절망 속에서도 가능성과 희망을 보여주는 사람입니다." },
    { text: "아무것도 혼자서 이룬 것은 없다.", author: "넬슨 만델라", category: "리더십", keyword: "alone nothing team together achieve", commentary: "위대한 성취 뒤에는 반드시 함께한 사람들이 있습니다. 겸손한 리더십의 핵심입니다." },
    { text: "비전 없이는 사람들이 사라진다.", author: "성경 (잠언 29:18)", category: "리더십", keyword: "vision people perish direction", commentary: "명확한 방향과 비전이 없으면 팀은 뿔뿔이 흩어지고 목적을 잃습니다." },

    // 창의성 (Creativity) - 확장
    { text: "모든 아이는 예술가다. 어른이 되어서도 예술가로 남는 것이 문제다.", author: "파블로 피카소", category: "창의성", keyword: "child artist adult creativity", commentary: "어른이 되면서 잃어버리는 자유로운 상상력과 두려움 없는 표현이야말로 창의성의 핵심입니다." },
    { text: "창의성은 실수를 저지를 용기에서 나온다.", author: "스콧 애덤스", category: "창의성", keyword: "creativity courage mistake risk", commentary: "완벽주의는 창의성의 적입니다. 틀릴 것을 두려워하지 않는 용기가 혁신을 만듭니다." },
    { text: "영감이 찾아올 때까지 기다리지 마라. 먼저 시작하면 영감이 따라온다.", author: "잭 런던", category: "창의성", keyword: "inspiration start first action follows", commentary: "뮤즈를 기다리는 것이 아니라 먼저 행동을 시작하면 창의성이 흘러나옵니다." },
    { text: "당신이 꿈꾸는 모든 것은 현실의 저편에 있다.", author: "파울로 코엘료", category: "창의성", keyword: "dream beyond reality create", commentary: "상상과 현실의 경계를 허무는 것이 모든 창조적 행위의 출발점입니다." },
    { text: "예술가란 세상을 다른 방식으로 보는 사람이다.", author: "레오나르도 다빈치", category: "창의성", keyword: "artist different see world perspective", commentary: "창의성은 특별한 재능이 아니라 세상을 다르게 바라보는 시각의 문제입니다." },
    { text: "복사하지 말고 훔쳐라. 예술가는 영향을 받는다. 위대한 예술가는 훔친다.", author: "스티브 잡스", category: "창의성", keyword: "steal inspired great artist copy", commentary: "다른 좋은 것들을 자신만의 방식으로 재조합하고 재창조하는 것이 진정한 창의성입니다." },
    { text: "창의력이 없다고 생각하는 사람은 창의적이 될 수 없다.", author: "에드워드 드 보노", category: "창의성", keyword: "creative believe think become", commentary: "창의성은 신념에서 시작됩니다. 스스로 창의적이라고 믿는 것이 첫 번째 단계입니다." },
    { text: "비어있는 캔버스가 예술가를 두렵게 하지만, 채워진 캔버스는 아무도 두렵게 하지 않는다.", author: "빈센트 반 고흐", category: "창의성", keyword: "blank canvas fear start artist", commentary: "시작의 두려움은 창의적 작업의 일부입니다. 그 두려움을 인정하고 첫 획을 그으세요." },
    { text: "최고의 아이디어는 사무실 밖에서 온다.", author: "제프 베조스", category: "창의성", keyword: "best ideas outside office walk", commentary: "산책, 여행, 대화 등 다양한 경험이 창의적 아이디어의 원천이 됩니다." },
    { text: "한계는 당신의 상상력 안에만 있다.", author: "버진 그룹 리처드 브랜슨", category: "창의성", keyword: "limits imagination only boundary", commentary: "실질적인 제약보다 우리 마음속의 한계가 더 큰 장벽입니다. 먼저 상상하세요." },
    { text: "불편함은 모든 창의적 진화의 어머니다.", author: "빌리 아이쉬", category: "창의성", keyword: "discomfort mother creativity evolution", commentary: "익숙한 것에서 벗어나 불편한 영역에 발을 들일 때 진정한 창의적 성장이 시작됩니다." },

    // 변화 (Change) - 확장
    { text: "변화는 불가피하다. 성장은 선택이다.", author: "존 맥스웰", category: "변화", keyword: "change inevitable growth choice", commentary: "세상의 변화는 막을 수 없지만, 그 변화 속에서 성장할지는 우리가 선택할 수 있습니다." },
    { text: "과거는 변경할 수 없다. 미래는 아직 오지 않았다. 당신이 바꿀 수 있는 것은 지금뿐이다.", author: "알랜 랙킨", category: "변화", keyword: "change now only present control", commentary: "변화의 유일한 시점은 지금 이 순간입니다. 과거의 후회나 미래의 걱정 대신 현재에 집중하세요." },
    { text: "우주에서 가장 영속적인 것은 변화다.", author: "헤라클레이토스", category: "변화", keyword: "permanent universe change flux", commentary: "만물은 끊임없이 변합니다. 변화를 거부하지 않고 그 흐름에 함께하는 것이 지혜입니다." },
    { text: "진정한 변화는 감각이 아닌 통찰에서 온다.", author: "토마스 쿤", category: "변화", keyword: "change insight paradigm shift revolution", commentary: "겉으로 드러나는 현상보다 세계관 자체를 바꾸는 '패러다임 전환'이 진정한 변화입니다." },
    { text: "당신이 원하는 세상이 되기 위해 당신 자신이 변하라.", author: "레오 톨스토이", category: "변화", keyword: "be change world you want", commentary: "간디와 같은 맥락. 세상의 변화는 자기 자신의 변화에서부터 시작됩니다." },
    { text: "변화를 즐겨라. 변화 속에 기회가 있다.", author: "마윈 (잭 마)", category: "변화", keyword: "enjoy change opportunity inside", commentary: "알리바바 창업자 잭 마는 모든 큰 변화 속에 숨어있는 기회를 포착하는 안목을 강조합니다." },
    { text: "성장하지 않는 것은 천천히 죽어가는 것이다.", author: "브로니 웨어", category: "변화", keyword: "grow or die stagnation death", commentary: "'임종을 앞둔 사람들의 5가지 후회'의 저자가 전하는 지속적 성장의 필요성입니다." },
    { text: "세상을 바꾸는 데 한 사람으로도 충분하다.", author: "마가렛 미드", category: "변화", keyword: "one person change world enough", commentary: "역사는 소수의 헌신적인 사람들이 세상을 바꿔왔음을 보여줍니다. 당신도 그 한 명이 될 수 있습니다." },
    { text: "변화에 맞서지 마라. 변화와 함께 춤추어라.", author: "알랜 와츠", category: "변화", keyword: "dance with change embrace flow", commentary: "저항은 에너지 낭비입니다. 변화의 흐름을 이해하고 그것을 활용하는 것이 지혜입니다." },
    { text: "낡은 방식으로는 새로운 결과를 얻을 수 없다.", author: "알베르트 아인슈타인", category: "변화", keyword: "new results old ways cannot", commentary: "다른 결과를 원한다면 행동 방식을 바꾸는 것이 유일한 방법입니다." },

    // 꿈 (Dreams) - 확장
    { text: "꿈을 꾸어야 현실이 된다.", author: "요한 볼프강 폰 괴테", category: "꿈", keyword: "dream reality goethe become", commentary: "독일의 대문호 괴테는 모든 위대한 현실은 먼저 꿈으로 시작했다는 것을 역설합니다." },
    { text: "세상을 바꿀 수 있다고 생각하는 사람들이 실제로 세상을 바꾼다.", author: "스티브 잡스", category: "꿈", keyword: "believe change world actually do", commentary: "미쳤다는 소리를 들을 만큼 큰 꿈을 가진 사람들이 역사를 만들어 왔습니다." },
    { text: "꿈이 없는 사람은 자신이 어디로 가는지 모르는 사람이다.", author: "힐러리 클린턴", category: "꿈", keyword: "dream direction know where go", commentary: "꿈은 인생의 나침반입니다. 명확한 꿈이 있어야 매 순간의 선택이 방향을 가집니다." },
    { text: "실현 가능한 꿈은 꿈이 아니다. 불가능해 보이는 것을 꿈꾸어야 한다.", author: "루이스 캐럴", category: "꿈", keyword: "impossible dream big enough", commentary: "'이상한 나라의 앨리스'를 쓴 캐럴처럼, 가장 위대한 것들은 불가능처럼 보이는 꿈에서 탄생합니다." },
    { text: "꿈꾸기를 멈추지 않는 한, 당신의 나이는 문제가 되지 않는다.", author: "세사르 차베스", category: "꿈", keyword: "dream never too old age stop", commentary: "꿈에는 나이 제한이 없습니다. 언제든 새로운 꿈을 꾸고 시작할 수 있습니다." },
    { text: "충분히 크게 꿈꾸지 않으면, 충분히 크게 살 수 없다.", author: "윌리엄 포크너", category: "꿈", keyword: "big dream big life live", commentary: "꿈의 크기가 인생의 크기를 결정합니다. 한계 없이 꿈을 키우세요." },
    { text: "당신의 꿈이 당신을 두렵게 만들지 않는다면, 그것은 충분히 크지 않은 것이다.", author: "엘런 존슨 설리프", category: "꿈", keyword: "dream scary big enough fear", commentary: "진정으로 위대한 꿈은 약간의 두려움과 함께 옵니다. 그 두려움이 꿈이 충분히 크다는 신호입니다." },
    { text: "꿈이 없으면 비전이 없고, 비전이 없으면 방향이 없다.", author: "존 맥스웰", category: "꿈", keyword: "dream vision direction purpose", commentary: "꿈 → 비전 → 방향 → 행동. 모든 위대한 여정은 꿈에서 출발합니다." },
    { text: "내일은 더 나은 오늘이 될 것이라는 꿈을 꾸어라.", author: "칼릴 지브란", category: "꿈", keyword: "tomorrow better today hope dream", commentary: "현실이 힘들더라도 더 나은 내일을 꿈꾸는 힘이 오늘을 버티게 해줍니다." },
    { text: "꿈을 실현하는 유일한 방법은 잠에서 깨어나는 것이다.", author: "조이 M. 에드워즈", category: "꿈", keyword: "dream realize wake up action", commentary: "꿈은 자는 동안 꾸는 것이 아니라 깨어나 행동할 때 현실이 됩니다." },

    // 시간 (Time) - 확장
    { text: "지금이 당신이 가진 전부다.", author: "에크하르트 톨레", category: "시간", keyword: "now all you have present", commentary: "'지금 이 순간의 힘'의 저자. 과거와 미래는 마음속의 개념일 뿐, 실제 삶은 지금만 있습니다." },
    { text: "시간은 가장 귀한 것이다. 왜냐하면 그것은 다시 돌아오지 않으니까.", author: "대 플리니우스", category: "시간", keyword: "time most precious irreversible", commentary: "한번 지나간 시간은 절대 되찾을 수 없습니다. 지금 이 순간이 가장 소중한 이유입니다." },
    { text: "시간을 투자하는 방법이 곧 삶을 투자하는 방법이다.", author: "스티브 잡스", category: "시간", keyword: "time invest life invest same", commentary: "어디에 시간을 쓰는가가 어떤 삶을 사는가를 결정합니다. 시간이 곧 인생입니다." },
    { text: "5분 전에 도착하는 것은 정시다. 정시에 도착하는 것은 늦은 것이다.", author: "비비 아이비슨", category: "시간", keyword: "time early punctual respect", commentary: "시간 약속을 지키는 것은 상대방에 대한 존중의 표현입니다." },
    { text: "지금 하지 않으면 언제 할 것인가?", author: "힐렐", category: "시간", keyword: "now if not when action", commentary: "미루는 습관은 꿈을 죽이는 가장 조용한 방법입니다. 지금 당장 시작하세요." },
    { text: "세월은 기다려주지 않는다.", author: "초서", category: "시간", keyword: "time waits for no one fleeting", commentary: "시간은 누구를 위해서도 멈추지 않습니다. 지금 이 순간에 최선을 다해야 합니다." },
    { text: "인생은 짧고 예술은 길다.", author: "히포크라테스", category: "시간", keyword: "life short art long ars longa", commentary: "의학의 아버지 히포크라테스가 말한 삶의 유한성. 우리의 배움과 창조는 생을 넘어 이어집니다." },
    { text: "어제는 역사다. 내일은 신비다. 오늘은 선물이다. 그래서 영어로 '현재'를 Present라고 한다.", author: "엘레오노르 루스벨트", category: "시간", keyword: "yesterday tomorrow today present gift", commentary: "오늘이라는 선물을 충분히 누리는 것이 가장 지혜로운 삶의 태도입니다." },
    { text: "10년 후 당신이 오늘을 돌아볼 때, 그 후회가 없도록 지금 최선을 다하라.", author: "제프 베조스", category: "시간", keyword: "ten years future regret best now", commentary: "아마존 창업 결정을 내릴 때 베조스는 '후회 최소화 프레임워크'를 사용했다고 합니다." },
    { text: "가장 중요한 일에 시간을 사용하고, 나머지 시간은 그냥 흘러가게 하라.", author: "고도 우시로", category: "시간", keyword: "most important time flow rest", commentary: "모든 일을 다 잘하려 하지 말고, 가장 중요한 것에 집중하는 시간 관리법입니다." },

    // 책 (Books) - 확장
    { text: "독서는 마음을 위한 운동이다.", author: "조셉 애디슨", category: "책", keyword: "reading exercise mind body", commentary: "책을 읽는 행위는 마음의 근육을 키우는 가장 효과적인 정신적 훈련입니다." },
    { text: "좋은 책은 두 번 읽어야 한다. 처음에는 생각 없이, 두 번째에는 깊이 생각하며.", author: "탈무드", category: "책", keyword: "good book twice read deep", commentary: "책을 깊이 소화하려면 반복해서 읽으며 다양한 층위의 의미를 탐구해야 합니다." },
    { text: "나는 책에서 고독의 즐거움을 발견했다.", author: "헤르만 헤세", category: "책", keyword: "books solitude pleasure discover", commentary: "'데미안'의 저자 헤세는 책 속에서 혼자만의 아름다운 세계를 발견했습니다." },
    { text: "당신이 읽는 것이 당신이 생각하는 방식을 만든다.", author: "올리버 웬들 홈스", category: "책", keyword: "read think shape mind way", commentary: "우리가 어떤 책을 읽는가가 우리의 사고방식과 세계관을 형성합니다." },
    { text: "좋은 책 한 권을 읽지 않은 날은 나쁜 날이다.", author: "에디슨 로비어", category: "책", keyword: "good book day without bad", commentary: "하루에 조금씩이라도 책을 읽는 습관이 평생에 걸쳐 엄청난 차이를 만들어냅니다." },
    { text: "책은 인류가 발명한 가장 훌륭한 타임머신이다.", author: "게리 폴슨", category: "책", keyword: "books time machine human invention best", commentary: "책을 통해 우리는 수천 년 전 현인들의 생각을 직접 만날 수 있습니다." },
    { text: "독서는 마음의 양식이고, 운동은 몸의 양식이다.", author: "조지프 애디슨", category: "책", keyword: "reading food mind exercise body", commentary: "지성과 신체 모두를 꾸준히 단련해야 건강한 삶을 살 수 있습니다." },
    { text: "작가는 독자를 위해 쓰지만, 독자는 자신을 위해 읽는다.", author: "조나단 프랜즌", category: "책", keyword: "writer reader for self discover", commentary: "같은 책이라도 독자마다 다른 의미로 받아들입니다. 독서는 자기 발견의 여정입니다." },
    { text: "모든 책은 다음 책으로 이어지는 문이다.", author: "스티브 킹", category: "책", keyword: "every book door next reading", commentary: "독서의 즐거움은 하나의 책이 또 다른 책으로, 또 다른 세계로 우리를 이끄는 데 있습니다." },

    // 영화 (Movies) - 확장
    { text: "힘이 세다고 강한 게 아니야. 올바른 일을 위해 쓸 때 강한 거야.", author: "영화 '캡틴 아메리카'", category: "영화", keyword: "strength righteous use hero", commentary: "진정한 힘은 크기나 능력이 아니라 그것을 올바른 목적을 위해 사용하는 데 있습니다." },
    { text: "그냥 헤엄쳐. 계속 헤엄쳐. 헤엄쳐.", author: "영화 '니모를 찾아서'", category: "영화", keyword: "keep swimming moving forward dory", commentary: "도리의 단순하지만 강력한 메시지. 어려운 상황에서도 포기하지 않고 계속 나아가는 것이 전부입니다." },
    { text: "삶은 우리가 만드는 것이다. 항상 그래왔고, 항상 그럴 것이다.", author: "영화 '어른 그랜마 모지스'", category: "영화", keyword: "life make create always", commentary: "삶은 주어지는 것이 아니라 매 순간 우리가 선택하고 만들어가는 것입니다." },
    { text: "당신이 무엇을 믿는지가 당신이 누구인지를 결정한다.", author: "영화 '스파이더맨'", category: "영화", keyword: "believe who you are identity", commentary: "믿음이 행동을 만들고, 행동이 사람을 만듭니다. 무엇을 믿느냐가 정체성을 결정합니다." },
    { text: "지금 하지 않으면 아무것도 변하지 않는다.", author: "영화 '인사이드 아웃'", category: "영화", keyword: "now change nothing action", commentary: "감정을 인정하고 직면하는 것, 그것이 진정한 변화의 시작입니다." },
    { text: "기억해, 넌 원하는 것보다 강하고, 용감하고, 더 똑똑하다.", author: "영화 '곰돌이 푸'", category: "영화", keyword: "stronger braver smarter than think", commentary: "우리는 종종 자신의 잠재력을 과소평가합니다. 당신은 생각보다 훨씬 능력 있는 사람입니다." },
    { text: "오늘은 당신의 인생의 첫날이다.", author: "영화 '더 첫날'", category: "영화", keyword: "today first day life fresh start", commentary: "매일을 새로운 시작으로 맞이하면 과거의 무게에서 자유로워질 수 있습니다." },
    { text: "우리가 원하는 대로 될 수 없지만, 우리가 될 수 있는 모든 것이 될 수 있다.", author: "영화 '모아나'", category: "영화", keyword: "become all can be potential moana", commentary: "한계와 역할에 갇히지 않고 자신의 가능성 전부를 펼치는 것이 삶의 목표입니다." },
    { text: "내가 누구인지는 내가 무엇을 했는지가 아니라, 내가 무엇을 하기로 선택했는지에 달려있다.", author: "영화 '미 비포 유'", category: "영화", keyword: "identity choose what do future", commentary: "과거가 아닌 현재의 선택이 우리의 정체성을 만들어갑니다." },
    { text: "진짜 마법은 그것을 믿는 사람 안에 있다.", author: "영화 '메리 포핀스'", category: "영화", keyword: "real magic believe inside you", commentary: "신념과 상상력이 있는 곳에서 기적이 일어납니다. 가능성을 믿는 것이 첫 번째 마법입니다." },
    { text: "한 사람이 차이를 만들 수 있고, 모든 사람이 노력해야 한다.", author: "영화 '아이언맨'", category: "영화", keyword: "one person difference everyone try", commentary: "세상의 변화는 모든 개인의 노력에서 시작됩니다. 당신의 행동이 중요합니다." },
    { text: "우리가 누구를 보내든, 거기에 이미 누군가가 있을 것이다.", author: "영화 '컨택트'", category: "영화", keyword: "contact alien connection hope", commentary: "우주를 향한 인류의 탐구는 결국 서로를 이해하고 연결하려는 깊은 욕구에서 비롯됩니다." },

    // 드라마 (Drama) - 확장
    { text: "하루하루 열심히 살다 보면, 언젠가 빛나는 날이 온다.", author: "드라마 '나의 아저씨'", category: "드라마", keyword: "everyday shine day come effort", commentary: "평범한 하루하루를 묵묵히 살아가는 것의 소중함과 그 끝에 오는 빛을 이야기합니다." },
    { text: "상처를 숨기지 마라. 상처가 당신을 강하게 만들었으니까.", author: "드라마 '디어 마이 프렌즈'", category: "드라마", keyword: "wound hide strong made scar", commentary: "우리의 상처는 부끄러운 것이 아니라, 삶을 통과한 증거이자 강함의 원천입니다." },
    { text: "포기는 배추를 셀 때나 쓰는 말이야.", author: "드라마 '드래곤볼' (번안)", category: "드라마", keyword: "never give up fight spirit", commentary: "포기라는 선택지 자체를 지워버리는 강한 의지를 유머러스하게 표현한 명대사입니다." },
    { text: "사는 게 전쟁이라고? 아니. 사는 게 오히려 다행이야.", author: "드라마 '나빌레라'", category: "드라마", keyword: "life war lucky alive grateful", commentary: "어떤 힘든 상황에서도 살아있음 자체를 다행으로 여기는 긍정적 시각을 전합니다." },
    { text: "늦었다고 생각할 때가 가장 이른 때다.", author: "드라마 '나빌레라'", category: "드라마", keyword: "late think earliest time start", commentary: "70대에 발레를 시작한 주인공처럼, 무언가를 시작하기에 늦은 때는 없습니다." },
    { text: "버티다 보면 때가 온다. 그러니 지금 버텨라.", author: "드라마 '스카이캐슬'", category: "드라마", keyword: "endure time comes hold on", commentary: "극한의 압박 속에서도 포기하지 않고 버텨낼 때 기회가 찾아옵니다." },
    { text: "약자에게도 강자에게도 흔들리지 않는 사람이 가장 강한 사람이다.", author: "드라마 '미스터 션샤인'", category: "드라마", keyword: "strong weak powerful unchanged steady", commentary: "어떤 압력에도 자신의 중심을 잃지 않는 것이 진정한 강인함입니다." },
    { text: "사람이 사람에게 가장 잔인한 것은 희망을 빼앗는 것이다.", author: "드라마 '비밀의 숲'", category: "드라마", keyword: "cruel take hope away human", commentary: "희망은 삶을 지탱하는 기둥입니다. 그것을 지키는 것이 서로를 향한 최소한의 예의입니다." },
    { text: "나 같은 사람도 괜찮아질 수 있어요?", author: "드라마 '이상한 변호사 우영우'", category: "드라마", keyword: "someone like me okay get better", commentary: "다름을 차이가 아닌 다양성으로 바라보며, 모든 사람이 괜찮아질 수 있다는 희망의 메시지입니다." },
    { text: "행복은 먼 곳에 있는 게 아니야. 이미 내 곁에 있어.", author: "드라마 '슬기로운 의사생활'", category: "드라마", keyword: "happiness not far already here beside", commentary: "바쁜 일상 속에서 곁에 있는 소중한 사람들과의 행복을 발견하는 것이 삶의 지혜입니다." },

    // 투자 (Investing) - 확장
    { text: "경제적 자유는 돈이 많은 것이 아니라 선택이 많은 것이다.", author: "로버트 기요사키", category: "투자", keyword: "financial freedom choice not much money", commentary: "'부자 아빠 가난한 아빠'의 저자. 진정한 부는 선택의 자유를 갖는 것입니다." },
    { text: "돈이 돈을 벌게 하라. 당신이 쉬는 동안 돈이 일하게 하라.", author: "알렉산더 대왕", category: "투자", keyword: "money work passive income sleep", commentary: "수동적 소득의 힘. 자산이 일하게 만드는 것이 장기적 부의 핵심입니다." },
    { text: "투자에서 가장 중요한 것은 IQ가 아니라 기질이다.", author: "워런 버핏", category: "투자", keyword: "investment temperament not IQ mindset", commentary: "시장 변동성에 흔들리지 않는 감정적 안정성이 투자 성공의 가장 중요한 요소입니다." },
    { text: "분산 투자는 무지에 대한 방어다. 자신이 무엇을 하는지 알면 분산할 필요가 없다.", author: "워런 버핏", category: "투자", keyword: "diversification ignorance knowledge focus", commentary: "충분한 연구와 확신이 있는 투자에 집중하는 것이 버핏의 역발상 투자 원칙입니다." },
    { text: "시장을 이기려 하지 마라. 시장과 함께하라.", author: "존 보글", category: "투자", keyword: "market beat with index fund vanguard", commentary: "뱅가드 창업자 보글의 인덱스 펀드 철학. 시장 전체를 사는 것이 장기적으로 최선입니다." },
    { text: "최고의 투자는 자기 자신에 대한 투자다.", author: "워런 버핏", category: "투자", keyword: "best investment yourself skills knowledge", commentary: "버핏이 가장 강조하는 투자. 자신의 능력과 지식에 투자하는 것이 가장 높은 수익을 줍니다." },
    { text: "시간이 당신 편이 되도록 하라. 일찍 시작하고 오래 유지하라.", author: "찰리 멍거", category: "투자", keyword: "time ally start early hold long", commentary: "복리의 마법은 시간과 인내심이 있어야 발휘됩니다. 일찍 시작할수록 유리합니다." },

    // 한국 위인들의 명언
    { text: "배움은 날이 부족하고, 가르침은 힘이 부족하다.", author: "세종대왕", category: "지혜", keyword: "learning teaching never enough", commentary: "한글을 창제한 세종대왕의 배움에 대한 열정. 배움과 가르침에는 끝이 없습니다." },
    { text: "신에게는 아직 열두 척의 배가 있사옵니다.", author: "이순신", category: "용기", keyword: "twelve ships still have courage", commentary: "명량해전 전 이순신 장군의 불굴의 의지. 어떤 절망적 상황에서도 포기하지 않는 용기입니다." },
    { text: "나의 죽음을 적에게 알리지 마라.", author: "이순신", category: "용기", keyword: "death enemy do not tell last battle", commentary: "마지막 순간까지 나라를 위해 헌신한 이순신의 정신. 자신보다 대의를 앞세운 위대한 희생입니다." },
    { text: "우리가 잘 된다는 것은 남의 것을 빼앗는 것이 아니라 우리 스스로 잘 되는 것이다.", author: "김구", category: "인생", keyword: "success self reliance not others", commentary: "백범 김구 선생의 자립 정신. 진정한 성공은 타인의 것을 취하는 것이 아닌 스스로 일어서는 것입니다." },
    { text: "나는 우리나라가 세계에서 가장 아름다운 나라가 되기를 원한다.", author: "김구", category: "꿈", keyword: "beautiful country dream nation", commentary: "물질적 강국이 아닌 문화적으로 아름다운 나라를 꿈꾼 백범의 고귀한 비전입니다." },

    // 과학자들의 명언
    { text: "공상과 현실 사이의 거리는 노력으로 채워진다.", author: "마리 퀴리", category: "성공", keyword: "fantasy reality filled effort work", commentary: "두 번 노벨상을 받은 마리 퀴리는 불가능해 보이는 꿈도 노력으로 현실이 된다는 것을 증명했습니다." },
    { text: "나는 실험실에서 나를 잊었을 때 가장 좋은 결과를 얻었다.", author: "마리 퀴리", category: "창의성", keyword: "best results forget self lab flow", commentary: "완전한 몰입 상태, 즉 '플로우'에서 최고의 창의적 성과가 나옵니다." },
    { text: "과학이 없는 종교는 맹목적이고, 종교가 없는 과학은 절름발이다.", author: "알베르트 아인슈타인", category: "지혜", keyword: "science religion blind lame both need", commentary: "이성과 신념, 과학과 영성은 서로 대립이 아닌 보완 관계에 있습니다." },
    { text: "저는 특별히 똑똑하지 않습니다. 그저 문제를 더 오래 생각할 뿐입니다.", author: "알베르트 아인슈타인", category: "지혜", keyword: "smart long time think persistence", commentary: "천재도 결국 꾸준한 사고와 끈질긴 탐구의 결과입니다. 포기하지 않는 것이 재능입니다." },

    // 추가 영화 명대사
    { text: "피가 흘러도, 내 심장은 뛰고 있다. 살아있다는 게 이렇게 아프면서도 아름답다.", author: "영화 '1917'", category: "영화", keyword: "alive pain beautiful war survive", commentary: "생사의 경계에서 깨닫는 살아있음의 소중함. 고통 속에서도 아름다움을 발견하는 인간의 의지입니다." },
    { text: "시간은 평평하고 원형이다. 모든 것은 반복될 것이다.", author: "드라마 '트루 디텍티브'", category: "드라마", keyword: "time flat circle repeat philosophy", commentary: "철학적 시간관. 과거, 현재, 미래가 순환한다는 관점에서 현재의 소중함을 일깨웁니다." },
    { text: "혼자서는 영웅이 될 수 없다.", author: "영화 '어벤져스'", category: "리더십", keyword: "alone hero team avengers together", commentary: "어떤 위대한 업적도 혼자 이룰 수 없습니다. 팀워크가 진정한 영웅을 만듭니다." },
    { text: "우주에서 가장 강력한 힘은 사랑이다.", author: "영화 '인터스텔라'", category: "사랑", keyword: "universe powerful force love dimension", commentary: "과학과 이성을 초월하는 사랑의 힘. 그것이 시공간을 넘어서는 가장 근원적인 에너지입니다." },

    // ===== 500개 완성 추가 =====
    { text: "삶에서 중요한 것은 목적지가 아니라 여정이다.", author: "랄프 왈도 에머슨", category: "인생", keyword: "journey destination life", commentary: "결과만 보며 달려가다 보면 삶의 아름다운 순간들을 놓칩니다. 과정 자체를 즐기세요." },
    { text: "지금 이 순간을 사랑하라. 그것이 당신의 삶이다.", author: "에크하르트 톨레", category: "인생", keyword: "love moment your life now", commentary: "과거의 기억이나 미래의 기대가 아닌, 지금 이 순간이 실제 삶입니다." },
    { text: "당신 인생의 이야기를 쓸 수 있는 사람은 당신뿐이다.", author: "조앤 롤링", category: "인생", keyword: "story life write only you", commentary: "해리포터를 창조한 롤링은 어려운 환경에서도 자신만의 이야기를 써 내려갔습니다." },
    { text: "아름다운 삶은 누군가를 사랑하고, 무언가를 배우고, 무언가를 남기는 것이다.", author: "미겔 데 세르반테스", category: "인생", keyword: "beautiful life love learn leave", commentary: "'돈키호테'의 저자가 말하는 아름다운 삶의 세 가지 조건. 사랑, 배움, 유산입니다." },
    { text: "진정한 성공은 기쁨과 평화로움 속에서 일하는 것이다.", author: "파울로 코엘료", category: "성공", keyword: "true success joy peace work", commentary: "외부의 인정이 아닌 내면의 충만함이 수반될 때 진정한 성공입니다." },
    { text: "성공으로 가는 엘리베이터는 고장났다. 계단을 이용해야 한다.", author: "조 지라드", category: "성공", keyword: "elevator broken stairs success step", commentary: "빠르게 성공하는 지름길은 없습니다. 한 계단 한 계단 성실하게 오르는 것뿐입니다." },
    { text: "열정 없이는 위대함을 이룰 수 없다.", author: "랄프 왈도 에머슨", category: "성공", keyword: "passion greatness nothing without", commentary: "진심 어린 열정이 없으면 평범함을 벗어날 수 없습니다. 무엇이 당신을 불태우는지 찾으세요." },
    { text: "오늘을 살아라! 다른 날들은 저절로 따라온다.", author: "영화 '죽은 시인의 사회'", category: "영화", keyword: "carpe diem today live other days", commentary: "키팅 선생님이 전하는 'Carpe Diem'. 지금 이 순간에 충실하게 살라는 가장 강렬한 메시지입니다." },
    { text: "삶은 우리를 무릎 꿇게 하지만, 우리는 다시 일어선다.", author: "영화 '록키'", category: "영화", keyword: "life knock knees rise again", commentary: "챔피언이 되는 것은 얼마나 강하게 치느냐가 아니라 맞고도 다시 일어서느냐에 달려 있습니다." },
    { text: "자유가 최고의 동기다.", author: "영화 '브레이브하트'", category: "영화", keyword: "freedom best motivation brave", commentary: "진정한 자유를 위해 목숨을 건 윌리엄 월리스의 이야기. 자유는 인간의 가장 깊은 욕구입니다." },
    { text: "당신이 선택한 것이 당신을 정의한다.", author: "영화 '해리 포터와 비밀의 방'", category: "영화", keyword: "choices define you abilities", commentary: "재능보다 선택이 우리의 정체성을 만듭니다. 매 순간의 선택이 당신이 누구인지를 말해줍니다." },
    { text: "어차피 인생은 죽을 때까지 사는 거잖아요. 그냥 열심히 살면 되지요.", author: "드라마 '동백꽃 필 무렵'", category: "드라마", keyword: "life just live hard simple", commentary: "복잡하게 생각하지 않고 그냥 열심히 살아가는 단순하지만 강한 삶의 철학입니다." },
    { text: "이 또한 지나가리라.", author: "드라마 '도깨비'", category: "드라마", keyword: "this too shall pass goblin time", commentary: "영원한 고통도, 영원한 기쁨도 없습니다. 모든 것은 지나갑니다. 그것이 위로가 됩니다." },
    { text: "사람이 사람에게 해 줄 수 있는 가장 좋은 일은 옆에 있어 주는 것이다.", author: "드라마 '눈이 부시게'", category: "드라마", keyword: "best give person beside presence", commentary: "화려한 선물보다 그냥 곁에 있어주는 것이 가장 큰 위로이자 사랑입니다." },
    { text: "하루하루 열심히 살다 보면, 언젠가 빛나는 날이 온다.", author: "드라마 '나의 아저씨'", category: "드라마", keyword: "everyday shine day come effort", commentary: "평범한 하루하루를 묵묵히 살아가는 것의 소중함과 그 끝에 오는 빛을 이야기합니다." },
    { text: "인내가 없으면 어떤 일도 이룰 수 없다.", author: "허버트 스펜서", category: "지혜", keyword: "patience achieve nothing without", commentary: "진화론에 영향을 준 철학자 스펜서의 말. 모든 위대한 일에는 긴 인내의 시간이 필요합니다." },
    { text: "아는 사람은 말하지 않고, 말하는 사람은 알지 못한다.", author: "노자", category: "지혜", keyword: "know not speak tao wisdom", commentary: "도덕경의 역설. 진정한 지혜는 과시하지 않고 침묵 속에 깃들어 있습니다." },
    { text: "지혜로운 사람은 말보다 행동으로 가르친다.", author: "레오나르도 다빈치", category: "지혜", keyword: "wise teach action not words", commentary: "말만 많고 실천이 없는 사람보다 묵묵히 행동으로 보여주는 사람이 더 큰 가르침을 줍니다." },
    { text: "당신이 올바른 일을 하면 두려움은 사라진다.", author: "엘리너 루스벨트", category: "용기", keyword: "right thing fear disappear", commentary: "양심에 따른 옳은 행동은 두려움을 이기는 가장 강력한 힘입니다." },
    { text: "전진하지 않는 것이 가장 위험한 선택이다.", author: "조지 패튼", category: "용기", keyword: "advance safest stand still danger", commentary: "전쟁에서도 삶에서도 현상 유지는 결국 후퇴를 의미합니다. 계속 나아가야 합니다." },
    { text: "지금 이 순간에 감사하라. 그것이 모든 것을 바꾼다.", author: "마이스터 에크하르트", category: "행복", keyword: "grateful now moment change everything", commentary: "감사의 태도가 현실을 바꿉니다. 이미 가진 것을 인식하는 것이 행복의 비결입니다." },
    { text: "행복한 삶의 비결은 필요한 것을 원하는 것이다.", author: "세네카", category: "행복", keyword: "secret happy life want need stoic", commentary: "욕망을 줄이는 것이 아니라, 이미 가진 것을 원하도록 마음을 훈련하는 것이 스토아의 지혜입니다." },
    { text: "타인의 행복을 위해 일할 때, 당신 자신의 행복을 발견한다.", author: "달라이 라마", category: "행복", keyword: "others happiness work find own", commentary: "이타심이 역설적으로 자신에게 가장 큰 기쁨과 만족을 가져다줍니다." },
    { text: "당신이 없을 때도 팀이 잘 돌아간다면, 당신은 훌륭한 리더다.", author: "피터 드러커", category: "리더십", keyword: "team work without great leader", commentary: "진정한 리더십은 자신에 대한 의존을 만드는 것이 아니라 팀 자체의 역량을 키우는 것입니다." },
    { text: "칭찬은 공개적으로, 비판은 개인적으로.", author: "켄 블랜차드", category: "리더십", keyword: "praise public criticize private", commentary: "효과적인 리더십의 황금률. 공개 칭찬은 동기를 부여하고, 사적인 피드백은 성장을 돕습니다." },
    { text: "실패는 발명의 어머니다.", author: "토마스 에디슨", category: "창의성", keyword: "failure mother invention creation", commentary: "1000번의 실패 끝에 전구를 발명한 에디슨. 실패는 창조의 필수적인 과정입니다." },
    { text: "영감이 찾아올 때까지 기다리지 마라. 먼저 시작하면 영감이 따라온다.", author: "잭 런던", category: "창의성", keyword: "inspiration start first action follows", commentary: "뮤즈를 기다리는 것이 아니라 먼저 행동을 시작하면 창의성이 흘러나옵니다." },
    { text: "변화는 불가피하다. 성장은 선택이다.", author: "존 맥스웰", category: "변화", keyword: "change inevitable growth choice", commentary: "세상의 변화는 막을 수 없지만, 그 변화 속에서 성장할지는 우리가 선택할 수 있습니다." },
    { text: "성장하지 않는 것은 천천히 죽어가는 것이다.", author: "브로니 웨어", category: "변화", keyword: "grow or die stagnation", commentary: "'임종을 앞둔 사람들의 5가지 후회'의 저자가 전하는 지속적 성장의 필요성입니다." },
    { text: "꿈꾸는 자는 항상 두려움을 이긴다.", author: "헬렌 켈러", category: "꿈", keyword: "dreamer overcomes fear always", commentary: "시각과 청각 없이도 꿈을 통해 세상을 넓힌 헬렌 켈러의 삶이 이 말의 증거입니다." },
    { text: "오늘의 상상이 내일의 현실이 된다.", author: "니콜라 테슬라", category: "꿈", keyword: "today imagination tomorrow reality", commentary: "교류 전기를 상상으로 구현해 낸 테슬라처럼, 상상력은 미래를 여는 열쇠입니다." },
    { text: "잠자는 동안 꾸는 것이 꿈이 아니라, 당신을 잠 못 들게 하는 것이 꿈이다.", author: "A.P.J. 압둘 칼람", category: "꿈", keyword: "dream sleep awake keep passion", commentary: "인도의 전설적인 과학자 대통령이 말하는 진정한 꿈. 가슴 속 열정이 진짜 꿈입니다." },
    { text: "지금이 당신이 가진 전부다.", author: "에크하르트 톨레", category: "시간", keyword: "now all you have present moment", commentary: "과거와 미래는 마음속의 개념일 뿐, 실제 삶은 지금만 있습니다." },
    { text: "인생은 짧고 예술은 길다.", author: "히포크라테스", category: "시간", keyword: "life short art long ars longa", commentary: "의학의 아버지 히포크라테스가 말한 삶의 유한성. 우리의 배움과 창조는 생을 넘어 이어집니다." },
    { text: "10년 후 당신이 오늘을 돌아볼 때, 그 후회가 없도록 지금 최선을 다하라.", author: "제프 베조스", category: "시간", keyword: "ten years future regret best now", commentary: "아마존 창업 결정을 내릴 때 베조스는 '후회 최소화 프레임워크'를 사용했다고 합니다." },
    { text: "독서는 마음을 위한 운동이다.", author: "조셉 애디슨", category: "책", keyword: "reading exercise mind workout", commentary: "책을 읽는 행위는 마음의 근육을 키우는 가장 효과적인 정신적 훈련입니다." },
    { text: "나는 책에서 고독의 즐거움을 발견했다.", author: "헤르만 헤세", category: "책", keyword: "books solitude pleasure hesse", commentary: "'데미안'의 저자 헤세는 책 속에서 혼자만의 아름다운 세계를 발견했습니다." },
    { text: "하루 30분 독서가 당신의 인생을 바꾼다.", author: "워런 버핏", category: "책", keyword: "thirty minutes daily reading change life", commentary: "버핏은 매일 5~6시간을 독서에 투자합니다. 지식의 복리 효과를 믿기 때문입니다." },
    { text: "돈이 돈을 벌게 하라. 당신이 쉬는 동안 돈이 일하게 하라.", author: "로버트 기요사키", category: "투자", keyword: "money work passive income sleep", commentary: "'부자 아빠 가난한 아빠'의 저자. 수동적 소득 창출을 통해 재정적 자유를 얻는 원칙입니다." },
    { text: "최고의 투자는 자기 자신에 대한 투자다.", author: "워런 버핏", category: "투자", keyword: "best investment yourself skills knowledge", commentary: "버핏이 가장 강조하는 투자. 자신의 능력과 지식에 투자하는 것이 가장 높은 수익을 줍니다." },
    { text: "호랑이에게 물려가도 정신만 차리면 산다.", author: "한국 속담", category: "용기", keyword: "tiger mind compose survive crisis", commentary: "어떤 위기 상황에서도 정신을 잃지 않고 냉정함을 유지하면 살 길이 열립니다." },
    { text: "신에게는 아직 열두 척의 배가 있사옵니다.", author: "이순신", category: "용기", keyword: "twelve ships still have courage admiral", commentary: "명량해전 전 이순신 장군의 불굴의 의지. 어떤 절망적 상황에서도 포기하지 않는 용기입니다." },
    { text: "군자는 화이부동하고, 소인은 동이불화한다.", author: "공자", category: "지혜", keyword: "harmony agree not same petty differ", commentary: "진정한 지혜는 다름을 인정하면서도 조화를 이루는 것. 맹목적 동의는 소인의 태도입니다." },
    { text: "지족자부(知足者富). 만족할 줄 아는 자가 부자다.", author: "노자", category: "행복", keyword: "know enough rich satisfy content", commentary: "도덕경의 가르침. 더 많이 갖는 것보다 이미 가진 것에 만족하는 마음이 진정한 풍요입니다." },
    { text: "마음이 가는 곳에 에너지가 흐른다.", author: "부처", category: "창의성", keyword: "mind energy flows attention focus", commentary: "주의를 기울이는 것에 생명력이 생깁니다. 무엇에 집중하느냐가 현실을 만듭니다." },
    { text: "승리는 팀의 것이고 패배는 내 것이다.", author: "박지성", category: "리더십", keyword: "victory team defeat mine responsibility", commentary: "맨유에서 활약한 박지성의 리더십 철학. 공로는 나누고 책임은 혼자 지는 자세입니다." },
    { text: "나는 지금의 나를 이기기 위해 훈련한다.", author: "김연아", category: "성공", keyword: "train beat past self improve", commentary: "세계 최고의 피겨 여왕 김연아의 경쟁 철학. 타인이 아닌 어제의 자신이 진정한 경쟁자입니다." },
    { text: "이해받는 것은 축복이지만, 이해하는 것은 더 큰 축복이다.", author: "필립스 브룩스", category: "지혜", keyword: "understood blessing understand bigger empathy", commentary: "타인을 이해하려는 노력이 이해받기를 바라는 것보다 더 가치 있는 태도입니다." },
    { text: "사람은 사람에게 빛이 된다.", author: "세네카", category: "인생", keyword: "person light another human connection", commentary: "인간은 서로에게 가장 큰 위로이자 희망이 됩니다. 연결과 공동체의 소중함을 말합니다." },
    { text: "문제를 해결하는 것이 아니라 올바른 문제를 찾는 것이 더 중요하다.", author: "알베르트 아인슈타인", category: "지혜", keyword: "right problem find more important solve", commentary: "잘못된 문제에 완벽한 답을 내는 것보다, 올바른 질문을 찾는 것이 더 근본적인 지혜입니다." },
    { text: "지구는 우리 조상으로부터 물려받은 것이 아니라 우리 자녀들에게서 빌린 것이다.", author: "생텍쥐페리", category: "인생", keyword: "earth borrow children future generation", commentary: "미래 세대를 위해 지금 우리가 어떻게 지구를 돌봐야 하는지를 역설합니다." },
    { text: "늦었다고 생각할 때가 가장 이른 때다.", author: "드라마 '나빌레라'", category: "꿈", keyword: "late think earliest time start never", commentary: "70대에 발레를 시작한 주인공처럼, 무언가를 시작하기에 늦은 때는 없습니다." },
    { text: "지식은 힘이다.", author: "프랜시스 베이컨", category: "지혜", keyword: "knowledge power information bacon", commentary: "정보와 이해가 세상을 변화시키는 힘을 가집니다. 배움은 가장 강력한 도구입니다." },

    // ===== 500개 완성 마지막 추가 =====
    { text: "천재는 1%의 영감과 99%의 노력으로 만들어진다.", author: "토마스 에디슨", category: "성공", keyword: "genius inspiration effort sweat", commentary: "에디슨이 강조한 것은 재능이 아닌 끊임없는 노력과 시도입니다." },
    { text: "당신이 생각하는 것이 당신이 된다.", author: "부처", category: "인생", keyword: "what you think you become buddha", commentary: "마음이 현실을 창조합니다. 긍정적이고 위대한 생각이 위대한 삶을 만들어냅니다." },
    { text: "두 길이 갈라지는 숲 속에서 나는 사람이 덜 간 길을 택했다. 그리고 그것이 모든 것을 바꿔놓았다.", author: "로버트 프로스트", category: "인생", keyword: "road less traveled choice difference", commentary: "다수가 가는 길이 아닌 자신만의 길을 선택하는 용기가 삶의 방향을 바꿉니다." },
    { text: "나는 내가 원하는 것을 얻지 못했지만, 내가 필요한 것을 얻었다.", author: "롤링 스톤스", category: "인생", keyword: "want need get satisfaction life", commentary: "원하는 것과 필요한 것이 다를 때, 인생은 종종 더 지혜로운 선물을 줍니다." },
    { text: "좋은 사람이 되어라. 그것으로 충분하다.", author: "마르쿠스 아우렐리우스", category: "인생", keyword: "good person be enough stoic", commentary: "복잡한 성공 방정식보다 단순히 좋은 사람이 되려는 노력이 삶을 풍요롭게 합니다." },
    { text: "나는 내 운명의 주인이고 내 영혼의 선장이다.", author: "윌리엄 어니스트 헨리", category: "인생", keyword: "master fate captain soul destiny", commentary: "어떤 상황에서도 자신의 내면과 선택을 지배하는 것은 오직 자기 자신뿐입니다." },
    { text: "먼저 규칙을 배워라. 그런 다음 현명하게 어겨라.", author: "파블로 피카소", category: "창의성", keyword: "learn rules break wisely innovate", commentary: "기존의 형식을 완벽히 익힌 후에야 그것을 뛰어넘는 창의적 혁신이 가능합니다." },
    { text: "인생에서 가장 위험한 것은 너무 조심스럽게 사는 것이다.", author: "알프레드 앤 래드클리프", category: "용기", keyword: "dangerous cautious life too much risk", commentary: "지나친 안전 추구가 역설적으로 삶의 가능성을 가장 크게 제한합니다." },
    { text: "행복은 외부에 있지 않다. 오직 내 안에 있다.", author: "레프 톨스토이", category: "행복", keyword: "happiness not outside inside within", commentary: "재산, 명예, 타인의 인정에서 행복을 찾는 것은 영원히 채워지지 않는 항아리와 같습니다." },
    { text: "성공적인 사람이 되려 하지 말고, 가치 있는 사람이 되려 하라.", author: "알베르트 아인슈타인", category: "성공", keyword: "valuable not successful person worth", commentary: "성공을 목표로 삼기보다 사회에 가치를 제공하는 사람이 되면 성공은 자연스럽게 따릅니다." },
    { text: "고통이 없으면 성취도 없다.", author: "벤저민 프랭클린", category: "성공", keyword: "no pain no gain achievement", commentary: "미국 건국의 아버지 프랭클린이 강조한 노력과 희생 없는 성공은 없다는 진리입니다." },
    { text: "단순함이 궁극적인 정교함이다.", author: "레오나르도 다빈치", category: "창의성", keyword: "simplicity ultimate sophistication design", commentary: "복잡한 것을 단순하게 만드는 것이 진정한 탁월함입니다. 단순함 속에 깊이가 있습니다." },
    { text: "변화를 두려워하는 사람은 변화에 지배당한다.", author: "헤라클레이토스", category: "변화", keyword: "fear change dominated controlled", commentary: "변화를 받아들이고 적응하는 사람만이 변화의 물결을 탈 수 있습니다." },
    { text: "가장 긴 여정은 첫걸음에서 시작된다.", author: "노자", category: "꿈", keyword: "longest journey first step begin tao", commentary: "천 리 길도 한 걸음부터. 어떤 거대한 목표도 지금 내딛는 작은 첫걸음에서 시작됩니다." },
    { text: "배움에는 끝이 없다.", author: "미켈란젤로", category: "지혜", keyword: "learning never ends lifetime grow", commentary: "89세에도 배움을 멈추지 않은 미켈란젤로의 삶 자체가 이 말의 증거입니다." },
    { text: "친절함은 무료다. 무상으로 나누어줘라.", author: "오드리 헵번", category: "인생", keyword: "kindness free share give", commentary: "우아함의 상징 오드리 헵번이 평생 실천한 삶의 철학. 친절은 돈 없이도 세상을 바꿉니다." },
    { text: "당신이 될 수 있는 최고의 버전이 되어라.", author: "레아 미쉘", category: "인생", keyword: "best version yourself become potential", commentary: "타인과 비교하지 말고 어제의 나보다 더 나은 나를 만드는 것이 진정한 성장입니다." },
    { text: "사랑은 주는 것이지 받는 것이 아니다.", author: "에리히 프롬", category: "사랑", keyword: "love give not receive active", commentary: "'사랑의 기술'에서 프롬은 사랑을 능동적 행위로 정의합니다. 기다리지 말고 먼저 베푸세요." },
    { text: "가장 큰 모험은 내가 꿈꾸던 삶을 사는 것이다.", author: "오프라 윈프리", category: "꿈", keyword: "greatest adventure dream life live", commentary: "세상의 기준이 아닌 자신이 진정으로 원하는 삶을 사는 것이 가장 큰 모험입니다." },
    { text: "불행한 것은 당신에게 일어나는 일이 아니라 그것에 대한 당신의 반응이다.", author: "엡픽테토스", category: "행복", keyword: "unhappy not what happens reaction stoic", commentary: "스토아 철학의 핵심. 외부 사건은 통제할 수 없지만 반응은 선택할 수 있습니다." },
    { text: "나는 완벽하지 않다. 그래도 충분히 좋다.", author: "브레네 브라운", category: "행복", keyword: "imperfect enough good vulnerability", commentary: "완벽주의를 내려놓고 자신의 불완전함을 받아들이는 것이 진정한 용기이자 행복입니다." },
    { text: "매일 무언가 새로운 것을 배워라.", author: "벤저민 프랭클린", category: "지혜", keyword: "daily learn something new grow wisdom", commentary: "평생 학습의 태도를 유지한 프랭클린은 인쇄업자에서 정치가, 과학자까지 다양한 분야에서 성취했습니다." },
    { text: "당신의 가장 큰 두려움은 당신의 가장 큰 가능성의 문이다.", author: "마크 맨슨", category: "용기", keyword: "greatest fear greatest possibility door", commentary: "'신경 끄기의 기술'의 저자. 두려워하는 것이 바로 성장의 다음 단계를 가리킵니다." },
    { text: "미래는 준비하는 자의 것이다.", author: "루이 파스퇴르", category: "성공", keyword: "future prepared belongs chance meet", commentary: "기회는 준비된 사람에게 찾아옵니다. 행운은 준비와 기회가 만나는 지점입니다." },
    { text: "최고의 시간은 지금이다. 최고의 장소는 여기다. 최고의 사람은 당신 옆에 있는 사람이다.", author: "레프 톨스토이", category: "인생", keyword: "best time now place here person beside", commentary: "머나먼 과거나 미래, 다른 곳이 아닌 바로 지금 여기에 삶의 모든 것이 있습니다." },
    { text: "실수는 경험이다. 경험은 지식이다. 지식은 힘이다.", author: "테리 길레메츠", category: "지혜", keyword: "mistake experience knowledge power chain", commentary: "실수를 두려워하지 마세요. 그것이 경험이 되고 지식이 되어 당신을 강하게 만듭니다." },
    { text: "꿈꾸고, 믿고, 행동하라. 그것이 전부다.", author: "월트 디즈니", category: "꿈", keyword: "dream believe act all you need", commentary: "디즈니 왕국을 세운 월트 디즈니의 세 단어 공식. 상상 → 신념 → 행동이 현실을 만듭니다." },
    { text: "세상을 향해 미소 지으면 세상도 당신을 향해 미소 짓는다.", author: "한국 속담", category: "행복", keyword: "smile world smiles back kindness", commentary: "내가 세상에 보내는 에너지가 그대로 돌아옵니다. 긍정과 친절은 전염됩니다." },
    { text: "탁월함은 목표가 아니라 습관이다.", author: "아리스토텔레스", category: "성공", keyword: "excellence habit not goal daily", commentary: "한 번의 위대한 행동이 아니라 매일의 탁월한 습관이 쌓여 위대한 사람을 만듭니다." },
    { text: "모든 것이 가능하다. 불가능한 것도 시간이 걸릴 뿐이다.", author: "선 쯔", category: "성공", keyword: "everything possible impossible takes time", commentary: "포기만 하지 않으면 어떤 목표도 결국 이룰 수 있습니다. 단지 시간이 필요할 뿐입니다." },
    { text: "당신이 마음을 여는 순간, 새로운 세상이 열린다.", author: "마야 안젤루", category: "변화", keyword: "open mind new world begins", commentary: "닫힌 마음은 새로운 가능성을 차단합니다. 열린 자세가 인생을 바꾸는 첫 번째 단계입니다." },
    { text: "지금 당장 완벽하게 할 수 없다면, 지금 당장 최선을 다하라.", author: "존 우든", category: "성공", keyword: "perfect not now best now try", commentary: "완벽을 기다리지 말고 지금 할 수 있는 최선을 다하는 것이 성공의 시작입니다." },
    { text: "당신이 나누어줄 수 있는 것 중 가장 소중한 것은 시간이다.", author: "릭 워렌", category: "인생", keyword: "most precious share give time", commentary: "돈이나 물건보다 자신의 시간을 나누는 것이 가장 깊은 사랑과 관심의 표현입니다." },
    { text: "위대한 작품은 끝없는 연습의 결과다.", author: "파블로 피카소", category: "창의성", keyword: "great work endless practice result", commentary: "천재로 불린 피카소도 수만 점의 작품을 그리며 탁월함에 이르렀습니다." },
    { text: "나는 실패한 것이 아니다. 단지 10,000번의 방법이 통하지 않는다는 것을 발견했을 뿐이다.", author: "토마스 에디슨", category: "용기", keyword: "not fail found ten thousand not work", commentary: "실패를 새로운 발견으로 재정의하는 에디슨의 무한한 낙관주의가 전구를 탄생시켰습니다." },
    { text: "오늘 할 수 있는 일에 최선을 다하면, 내일은 더 잘 할 수 있을 것이다.", author: "마야 안젤루", category: "성공", keyword: "today best tomorrow better improve", commentary: "매일 조금씩 더 나아지려는 노력이 쌓여 놀라운 성장을 만들어냅니다." },
    { text: "사랑하는 일을 찾아라. 그러면 평생 하루도 일한 것 같지 않을 것이다.", author: "공자", category: "인생", keyword: "love work find never work day life", commentary: "열정이 있는 일을 직업으로 삼을 때 삶 전체가 의미로 가득 찹니다." },
    { text: "당신이 집중하는 것에 에너지가 흐른다.", author: "나폴레온 힐", category: "창의성", keyword: "energy flows focus attention power", commentary: "긍정적인 것에 집중하면 긍정적 에너지가 모이고, 원하는 것이 더 쉽게 이루어집니다." },
    { text: "책을 읽는 것은 다른 사람의 두뇌를 빌리는 것이다.", author: "데카르트", category: "책", keyword: "reading borrow brain another person", commentary: "독서를 통해 우리는 인류 최고의 지성들의 사고를 직접 체험할 수 있습니다." },
    { text: "내가 서 있는 곳이 세상의 중심이다.", author: "세종대왕", category: "인생", keyword: "where stand center world confident", commentary: "자신이 있는 자리에서 최선을 다하는 것이 세상 모든 곳에서 중심이 되는 방법입니다." },
    { text: "진정한 부는 돈에 있지 않고 지혜에 있다.", author: "솔로몬 왕", category: "지혜", keyword: "true wealth wisdom not money", commentary: "성경 속 가장 지혜로운 왕 솔로몬은 부보다 지혜를 구했고, 그로 인해 모든 것을 얻었습니다." },
    { text: "사랑은 동사다. 명사가 아니다.", author: "스티븐 코비", category: "사랑", keyword: "love verb not noun action", commentary: "사랑은 감정이 아니라 매일 실천하는 행동입니다. 사랑한다면 행동으로 보여주세요." },
    { text: "나는 내가 어떤 사람인지 알고 싶다. 그러기 위해 여행을 떠난다.", author: "마크 트웨인", category: "인생", keyword: "know who travel discover yourself", commentary: "새로운 환경과 경험이 우리의 진정한 자아를 발견하게 해줍니다." },
    { text: "노력하는 사람은 즐기는 사람을 이길 수 없다.", author: "공자", category: "성공", keyword: "work hard cannot beat enjoy passion", commentary: "의무감으로 하는 일보다 진정으로 즐기며 하는 일이 훨씬 더 높은 성취를 만듭니다." },
    { text: "당신이 기억될 방식으로 살아라.", author: "마야 안젤루", category: "인생", keyword: "remembered way live legacy", commentary: "삶을 마감할 때 어떤 사람으로 기억되고 싶은지를 생각하며 지금을 살아가세요." },
    { text: "숲 속에서 길을 잃으면, 나무 한 그루에 집착하지 말고 멀리 보라.", author: "노자", category: "지혜", keyword: "forest lost tree focus far big picture", commentary: "세부적인 것에 집착하기보다 전체적인 큰 그림을 보는 시야가 지혜로운 판단을 만듭니다." },
    { text: "작은 일에도 성심을 다하라. 큰 일도 작은 일의 쌓임이다.", author: "마더 테레사", category: "성공", keyword: "small things full heart great consist", commentary: "노벨 평화상 수상자 마더 테레사는 가장 작고 초라한 사람들을 섬기며 세상을 바꿨습니다." },
    { text: "위험은 회피할 수 있는 것이 아니다. 관리하는 것이다.", author: "피터 드러커", category: "투자", keyword: "risk not avoid manage control", commentary: "위험을 완전히 없앨 수는 없습니다. 현명하게 파악하고 관리하는 것이 최선입니다." },
    { text: "말보다 침묵이 더 많은 것을 말해줄 때가 있다.", author: "레프 톨스토이", category: "지혜", keyword: "silence speaks more than words sometimes", commentary: "진정성 있는 침묵이 수많은 말보다 더 깊은 진실과 이해를 전달할 수 있습니다." },
    { text: "오늘의 독서가 내일의 언어를 만든다.", author: "랄프 왈도 에머슨", category: "책", keyword: "today reading tomorrow language speech", commentary: "지금 읽는 책들이 미래에 당신이 생각하고 말하는 방식을 만들어갑니다." },
    { text: "나의 가장 큰 행복은 내가 선택한 사람들과 함께하는 것이다.", author: "알베르 카뮈", category: "행복", keyword: "greatest happiness chosen people together", commentary: "진정한 행복은 선택한 인간관계에서 옵니다. 함께하는 사람이 삶의 질을 결정합니다." },
    { text: "실패는 성공이 미루어진 것이다.", author: "비스와나단 아난드", category: "성공", keyword: "failure success postponed delayed", commentary: "체스 세계 챔피언 아난드처럼, 실패는 끝이 아니라 성공이 잠시 미뤄진 것뿐입니다." },
    { text: "어려운 길에 최고의 전망이 있다.", author: "한국 속담", category: "용기", keyword: "hardest road best view top", commentary: "쉬운 길에는 아름다운 경치가 없습니다. 힘든 여정 끝에 가장 위대한 풍경이 펼쳐집니다." },
    { text: "당신은 이미 충분히 강하다. 그것을 믿기만 하면 된다.", author: "영화 '뮬란'", category: "용기", keyword: "already strong enough believe mulan", commentary: "우리는 생각보다 훨씬 강한 존재입니다. 자신의 힘을 믿는 것이 가장 먼저입니다." },
    { text: "기다림도 하나의 행동이다.", author: "드라마 '이태원 클라쓰'", category: "인생", keyword: "waiting action too patient time", commentary: "때로는 전략적으로 기다리는 것이 가장 현명한 행동입니다. 인내는 힘입니다." },

    // ===== 최종 500+ 완성 =====
    { text: "혼자서 꾸는 꿈은 꿈에 불과하지만, 함께 꾸는 꿈은 현실이 된다.", author: "오노 요코", category: "꿈", keyword: "alone dream together reality become", commentary: "비틀즈의 존 레논과 함께 평화 운동을 펼친 오노 요코의 말. 꿈은 나눌 때 더 강해집니다." },
    { text: "재능은 신이 주는 것이다. 겸손하라. 명성은 사람이 주는 것이다. 감사하라.", author: "존 우든", category: "지혜", keyword: "talent god give humble fame people thank", commentary: "10번 NCAA 챔피언십을 달성한 코치의 지혜. 성공 앞에 겸손과 감사를 잃지 마세요." },
    { text: "지금 당장 떠날 수 없어도, 책을 펼치면 어디든 갈 수 있다.", author: "J.K. 롤링", category: "책", keyword: "travel anywhere open book magic", commentary: "해리포터의 작가 롤링은 가장 힘들었던 시절 도서관에서 피난처를 찾았습니다." },
    { text: "세상에서 가장 강한 사람은 자신을 이기는 사람이다.", author: "세네카", category: "용기", keyword: "strongest person overcome self conquer", commentary: "외부의 적을 이기는 것보다 자신의 욕망과 두려움을 다스리는 것이 더 어렵고 위대합니다." },
    { text: "어머니의 사랑은 세상의 어떤 힘보다도 강하다.", author: "어니스트 헤밍웨이", category: "사랑", keyword: "mother love strongest force world", commentary: "무조건적이고 헌신적인 부모의 사랑은 인간이 경험할 수 있는 가장 순수한 형태의 사랑입니다." },
    { text: "사람은 빵만으로 살 수 없다.", author: "성경 (마태복음 4:4)", category: "인생", keyword: "bread alone not live spirit meaning", commentary: "물질적 필요 외에 정신적, 영적 양식도 인간이 살아가는 데 꼭 필요합니다." },
    { text: "배우는 것을 멈추면 늙기 시작한다.", author: "헨리 포드", category: "지혜", keyword: "stop learning start aging old young", commentary: "포드 자동차의 창업자 헨리 포드는 평생 배움의 자세를 유지하며 혁신을 이어갔습니다." },
    { text: "우리가 할 수 없다고 생각하는 것을 우리가 할 수 있다는 것을 증명하라.", author: "엘리너 루스벨트", category: "용기", keyword: "prove cannot can possible try", commentary: "루스벨트 대통령의 부인이자 위대한 활동가. 불가능의 경계를 행동으로 허무는 것이 용기입니다." },
    { text: "기쁨은 나누면 두 배가 되고, 슬픔은 나누면 반이 된다.", author: "한국 속담", category: "행복", keyword: "joy double sorrow half share together", commentary: "혼자 간직하지 않고 함께 나눌 때 기쁨은 커지고 슬픔은 작아집니다." },
    { text: "작은 것에 감사하지 못하는 사람은 큰 것에도 감사하지 못한다.", author: "윌리엄 아더 워드", category: "행복", keyword: "small grateful big not either gratitude", commentary: "감사의 태도는 훈련입니다. 작은 것에 감사하는 습관이 전반적인 삶의 행복도를 높입니다." },
    { text: "당신이 원하는 것이 되어라. 세상은 그것을 필요로 한다.", author: "달라이 라마", category: "인생", keyword: "be what want world need you", commentary: "진정성 있는 자신의 모습이 세상에 필요한 기여를 합니다. 남의 기대가 아닌 자신의 본성을 따르세요." },
    { text: "나쁜 날도 좋은 날이다. 살아있기만 하다면.", author: "드라마 '나의 해방일지'", category: "행복", keyword: "bad day good alive grateful live", commentary: "어떤 하루든 살아있다는 것 자체가 이미 충분한 이유가 됩니다." },
    { text: "예술은 삶을 아름답게 만드는 것이 아니라 삶의 아름다움을 발견하는 것이다.", author: "로댕", category: "창의성", keyword: "art discover beauty life not make", commentary: "조각의 거장 로댕은 아름다움이 이미 세상에 있으며, 예술가는 그것을 드러낼 뿐이라고 봤습니다." },
    { text: "한 번도 실망한 적 없는 사람은 한 번도 사랑한 적 없는 사람이다.", author: "알프레드 로드 테니슨", category: "사랑", keyword: "disappointed never loved never either hurt", commentary: "사랑은 기쁨과 함께 상처와 실망도 가져옵니다. 그 모든 것이 사랑의 일부입니다." },
    { text: "당신이 오늘 심은 씨앗이 내일의 나무가 된다.", author: "중국 속담", category: "성공", keyword: "seed today tree tomorrow plant future", commentary: "오늘의 노력과 투자가 미래의 결실을 만듭니다. 지금 당장 씨앗을 심으세요." },
    { text: "정직이 최선의 방책이다.", author: "벤저민 프랭클린", category: "지혜", keyword: "honesty best policy integrity truth", commentary: "단기적으로 불리해 보여도 장기적으로 정직함이 가장 현명하고 유익한 전략입니다." },
    { text: "지금 하지 않으면, 언제 할 것인가? 당신이 아니면, 누가 할 것인가?", author: "힐렐 (탈무드)", category: "인생", keyword: "now not when you not who talmud", commentary: "행동을 미루거나 타인에게 미루는 것을 경계하는 탈무드의 핵심 가르침입니다." },
    { text: "과거는 바꿀 수 없지만, 과거를 바라보는 시각은 바꿀 수 있다.", author: "에픽테토스", category: "변화", keyword: "past cannot change perspective can stoic", commentary: "스토아 철학의 힘. 사건 자체가 아닌 해석을 바꾸는 것이 우리의 진정한 자유입니다." },
    { text: "당신이 남기는 것이 당신의 유산이다.", author: "게리 바이너척", category: "인생", keyword: "leave legacy behind impact life", commentary: "삶이 끝난 후 남는 영향력과 업적이 진정한 유산입니다. 지금부터 그것을 쌓아가세요." },
    { text: "모든 전문가는 한때 초보자였다.", author: "헬렌 헤이스", category: "성공", keyword: "every expert once beginner start", commentary: "지금 서툴더라도 포기하지 마세요. 모든 대가도 처음에는 아무것도 몰랐습니다." },
    { text: "가장 훌륭한 선물은 당신의 온전한 관심이다.", author: "짐 론", category: "사랑", keyword: "best gift full attention presence", commentary: "물질적 선물보다 상대방에게 온전히 집중하는 것이 가장 깊은 사랑의 표현입니다." },
    { text: "진정한 행복은 바깥에서 오는 것이 아니라 자신 안에서 자란다.", author: "루이즈 헤이", category: "행복", keyword: "true happiness outside inside grows within", commentary: "'치유하라'의 저자 루이즈 헤이는 내면의 평화와 자기 사랑이 행복의 근원임을 강조합니다." },
    { text: "우리가 보는 것은 우리가 찾는 것이다.", author: "레오 로스텐", category: "지혜", keyword: "see what look find perspective seek", commentary: "긍정적인 것을 찾으면 긍정적인 것이 보이고, 부정적인 것을 찾으면 부정적인 것이 보입니다." },
    { text: "당신의 한계는 당신이 정한다.", author: "피터 맥윌리엄스", category: "용기", keyword: "limits you set yourself define", commentary: "대부분의 한계는 외부가 아닌 우리 자신이 만든 것입니다. 그 한계를 의심하고 넘어서세요." },
    { text: "작은 친절이 세상을 바꾼다.", author: "마더 테레사", category: "인생", keyword: "small kindness changes world impact", commentary: "한 번의 작은 친절이 사람의 하루를, 나아가 삶을 바꿀 수 있습니다." },
    { text: "완성되지 않은 것이 더 나을 때가 있다.", author: "레오나르도 다빈치", category: "창의성", keyword: "unfinished better sometimes complete art", commentary: "다빈치는 수많은 작품을 미완성으로 남겼습니다. 완성보다 과정의 탐구가 더 소중할 수 있습니다." },
    { text: "성공한 이유는 포기하지 않은 것이다.", author: "마거릿 대처", category: "성공", keyword: "succeed reason never give up persist", commentary: "영국 최초의 여성 총리 대처는 수많은 반대에도 끝까지 나아가는 의지로 역사를 만들었습니다." },
    { text: "이 세상에서 가장 쉬운 일은 다른 사람을 비판하는 것이다.", author: "존 스타인벡", category: "지혜", keyword: "easiest criticize others world do", commentary: "노벨 문학상 수상자 스타인벡. 비판하기보다 이해하고 공감하는 것이 훨씬 어렵고 가치 있습니다." },
    { text: "두 사람이 함께 가면 더 빨리, 더 멀리 간다.", author: "아프리카 속담", category: "리더십", keyword: "together faster farther two people team", commentary: "협력과 공동체의 힘. 혼자보다 함께할 때 더 빠르고 더 멀리 갈 수 있습니다." },
    { text: "나는 매일 아침 새롭게 태어난다.", author: "마르쿠스 아우렐리우스", category: "변화", keyword: "every morning born new fresh start", commentary: "어제의 실패나 후회는 새벽과 함께 끝납니다. 매일 아침은 새로운 시작의 기회입니다." },
    { text: "예의 바름은 힘없는 자의 무기가 아니라 강한 자의 선택이다.", author: "마거릿 미드", category: "지혜", keyword: "politeness strong choice not weak", commentary: "진정으로 강한 사람은 예의를 지킬 여유가 있습니다. 무례함은 종종 내면의 약함을 드러냅니다." },
    { text: "시작이 절반이다.", author: "아리스토텔레스", category: "성공", keyword: "start half done beginning well begun", commentary: "시작하는 것 자체가 이미 절반을 완성한 것과 같습니다. 지금 바로 시작하세요." },
    { text: "최고의 의사는 자연이다.", author: "히포크라테스", category: "행복", keyword: "best doctor nature heal body mind", commentary: "자연과의 접촉이 몸과 마음을 치유하는 가장 근본적인 방법임을 2400년 전에 이미 알았습니다." },
    { text: "당신이 용서할 때, 당신은 자유로워진다.", author: "넬슨 만델라", category: "인생", keyword: "forgive free yourself prison hatred", commentary: "27년의 투옥 후에도 용서를 선택한 만델라. 용서는 타인을 위한 것이 아니라 자신을 위한 것입니다." },
    { text: "습관은 제2의 천성이다.", author: "아리스토텔레스", category: "성공", keyword: "habit second nature character destiny", commentary: "반복된 행동이 습관이 되고, 습관이 성격이 되고, 성격이 운명을 만듭니다." },
    { text: "배움은 보물이다. 어디서든 주인을 따른다.", author: "중국 속담", category: "지혜", keyword: "learning treasure follows owner everywhere", commentary: "돈이나 재산은 잃을 수 있지만, 지식과 지혜는 어디서든 당신과 함께합니다." },
    { text: "남을 이기는 사람은 강하다. 자신을 이기는 사람은 더욱 강하다.", author: "노자", category: "지혜", keyword: "overcome others strong self stronger tao", commentary: "타인과의 경쟁보다 자신의 내면을 다스리는 것이 더 큰 힘을 요구합니다." },
    { text: "꽃이 피는 것을 서두르지 마라. 시간이 되면 저절로 핀다.", author: "한국 속담", category: "인생", keyword: "flower bloom hurry time naturally patience", commentary: "모든 것에는 때가 있습니다. 조급해하지 말고 자연의 리듬을 믿으세요." },
    { text: "나쁜 것을 보지 않는 눈, 나쁜 것을 듣지 않는 귀, 나쁜 것을 말하지 않는 입.", author: "공자", category: "지혜", keyword: "see hear speak no evil wisdom", commentary: "공자의 삼불(三不). 불필요한 부정적 정보를 필터링하고 선한 것에 집중하는 지혜입니다." },
    { text: "당신이 만나는 모든 사람은 당신이 모르는 전쟁을 치르고 있다. 친절해라.", author: "이언 맥러런", category: "인생", keyword: "everyone fighting battle kindness unknown", commentary: "우리는 타인의 고통을 보지 못합니다. 그러므로 항상 친절하게 대하는 것이 현명합니다." },
    { text: "오직 교육만이 세상을 바꿀 수 있다.", author: "넬슨 만델라", category: "지혜", keyword: "only education change world powerful", commentary: "만델라는 가장 강력한 무기가 교육이라고 믿었습니다. 배움이 개인과 사회를 변화시킵니다." },
    { text: "당신의 인생은 당신이 집중하는 것의 총합이다.", author: "마르쿠스 아우렐리우스", category: "인생", keyword: "life sum what focus attention build", commentary: "무엇에 주의를 기울이느냐가 어떤 삶을 사느냐를 결정합니다. 집중하는 것이 현실이 됩니다." },
    { text: "비가 와야 무지개도 뜬다.", author: "돌리 파튼", category: "용기", keyword: "rain rainbow comes after storm hope", commentary: "컨트리 음악의 여왕 돌리 파튼. 어려움이 지나야 아름다운 결과가 찾아온다는 따뜻한 위로입니다." },
    { text: "감사함은 최고의 기도다.", author: "달라이 라마", category: "행복", keyword: "gratitude highest prayer thankful", commentary: "감사하는 마음이 기도이자 명상이며 행복의 원천입니다. 감사함을 일상으로 만드세요." },
    { text: "삶은 당신이 만들어가는 것이다. 항상 그래왔고, 앞으로도 그럴 것이다.", author: "그랜마 모지스", category: "인생", keyword: "life make create always been will be", commentary: "101세까지 그림을 그린 그랜마 모지스. 삶의 주도권은 언제나 자신에게 있습니다." },
    { text: "위대한 생각은 위대한 행동을 만든다.", author: "올리버 웬들 홈스", category: "성공", keyword: "great thought great action makes", commentary: "마음속에 위대한 것을 품는 것이 위대한 현실을 만드는 첫 번째 단계입니다." }
];
